void filters_builtin_effects_apply_and_write_artifacts() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  const std::vector<std::pair<std::string, std::string>> filters = {
      {"patchy.filters.brightness_contrast", "filter_brightness_contrast"},
      {"patchy.filters.grayscale", "filter_grayscale"},
      {"patchy.filters.desaturate", "filter_desaturate"},
      {"patchy.filters.auto_contrast", "filter_auto_contrast"},
      {"patchy.filters.soft_glow", "filter_soft_glow"},
      {"patchy.filters.punchy_color", "filter_punchy_color"},
      {"patchy.filters.noir", "filter_noir"},
      {"patchy.filters.cinematic_matte", "filter_cinematic_matte"},
      {"patchy.filters.vintage_fade", "filter_vintage_fade"},
      {"patchy.filters.sepia", "filter_sepia"},
      {"patchy.filters.threshold", "filter_threshold"},
      {"patchy.filters.posterize", "filter_posterize"},
      {"patchy.filters.box_blur", "filter_box_blur"},
      {"patchy.filters.sharpen", "filter_sharpen"},
      {"patchy.filters.unsharp_mask", "filter_unsharp_mask"},
      {"patchy.filters.gaussian_blur", "filter_gaussian_blur"},
      {"patchy.filters.motion_blur", "filter_motion_blur"},
      {"patchy.filters.radial_blur", "filter_radial_blur"},
      {"patchy.filters.edge_detect", "filter_edge_detect"},
      {"patchy.filters.emboss", "filter_emboss"},
      {"patchy.filters.glowing_edges", "filter_glowing_edges"},
      {"patchy.filters.twirl", "filter_twirl"},
      {"patchy.filters.wave", "filter_wave"},
      {"patchy.filters.pinch_bloat", "filter_pinch_bloat"},
      {"patchy.filters.clouds", "filter_clouds"},
      {"patchy.filters.pixelate", "filter_pixelate"},
      {"patchy.filters.color_halftone", "filter_color_halftone"},
      {"patchy.filters.film_grain", "filter_film_grain"},
      {"patchy.filters.vignette", "filter_vignette"},
  };

  for (const auto& [identifier, artifact_name] : filters) {
    auto document = make_filter_document();
    auto& pixels = document.layers().front().pixels();
    registry.apply(identifier, pixels);
    CHECK(!pixels.empty());
    write_bmp_artifact(artifact_name, document);
  }

  auto brightness_contrast = make_filter_document();
  const auto* original_brightness_contrast_px = brightness_contrast.layers().front().pixels().pixel(0, 0);
  const auto original_brightness_contrast_red = original_brightness_contrast_px[0];
  const auto original_brightness_contrast_green = original_brightness_contrast_px[1];
  const auto original_brightness_contrast_blue = original_brightness_contrast_px[2];
  registry.apply("patchy.filters.brightness_contrast", brightness_contrast.layers().front().pixels());
  const auto* brightness_contrast_px = brightness_contrast.layers().front().pixels().pixel(0, 0);
  CHECK(brightness_contrast_px[0] == original_brightness_contrast_red);
  CHECK(brightness_contrast_px[1] == original_brightness_contrast_green);
  CHECK(brightness_contrast_px[2] == original_brightness_contrast_blue);

  auto threshold = make_filter_document();
  registry.apply("patchy.filters.threshold", threshold.layers().front().pixels());
  const auto* threshold_px = threshold.layers().front().pixels().pixel(0, 0);
  CHECK(threshold_px[0] == 0);
  CHECK(threshold_px[1] == 0);
  CHECK(threshold_px[2] == 0);

  auto desaturate = make_filter_document();
  registry.apply("patchy.filters.desaturate", desaturate.layers().front().pixels());
  const auto* desaturated_px = desaturate.layers().front().pixels().pixel(3, 2);
  CHECK(desaturated_px[0] == desaturated_px[1]);
  CHECK(desaturated_px[1] == desaturated_px[2]);

  auto auto_contrast = make_filter_document();
  registry.apply("patchy.filters.auto_contrast", auto_contrast.layers().front().pixels());
  const auto* low_px = auto_contrast.layers().front().pixels().pixel(0, 0);
  const auto* high_px = auto_contrast.layers().front().pixels().pixel(31, 23);
  CHECK(low_px[0] == 0);
  CHECK(low_px[1] == 0);
  CHECK(low_px[2] == 0);
  CHECK(high_px[0] == 255);
  CHECK(high_px[1] == 255);
  CHECK(high_px[2] == 255);

  auto noir = make_filter_document();
  registry.apply("patchy.filters.noir", noir.layers().front().pixels());
  const auto* noir_px = noir.layers().front().pixels().pixel(10, 10);
  CHECK(noir_px[0] == noir_px[1]);
  CHECK(noir_px[1] == noir_px[2]);

  auto pin_blur = patchy::PixelBuffer(5, 5, patchy::PixelFormat::rgb8());
  pin_blur.pixel(2, 2)[0] = 255;
  pin_blur.pixel(2, 2)[1] = 255;
  pin_blur.pixel(2, 2)[2] = 255;
  registry.apply("patchy.filters.gaussian_blur", pin_blur);
  CHECK(pin_blur.pixel(2, 2)[0] > pin_blur.pixel(1, 2)[0]);
  CHECK(pin_blur.pixel(1, 2)[0] > 0);
  CHECK(pin_blur.pixel(2, 2)[0] < 255);

  auto unsharp = solid_rgb(5, 1, 40, 40, 40);
  for (std::int32_t x = 2; x < unsharp.width(); ++x) {
    auto* px = unsharp.pixel(x, 0);
    px[0] = 160;
    px[1] = 160;
    px[2] = 160;
  }
  registry.apply("patchy.filters.unsharp_mask", unsharp);
  CHECK(unsharp.pixel(1, 0)[0] < 40);
  CHECK(unsharp.pixel(2, 0)[0] > 160);

  auto motion = solid_rgb(31, 1, 0, 0, 0);
  motion.pixel(15, 0)[0] = 255;
  motion.pixel(15, 0)[1] = 255;
  motion.pixel(15, 0)[2] = 255;
  registry.apply("patchy.filters.motion_blur", motion);
  CHECK(motion.pixel(15, 0)[0] < 255);
  CHECK(motion.pixel(4, 0)[0] > 0);
  CHECK(motion.pixel(26, 0)[0] > 0);

  const auto make_transparent_red_stroke = [] {
    auto pixels = solid_rgba(65, 65, 0, 0, 0, 0);
    for (std::int32_t y = 10; y <= 54; ++y) {
      for (std::int32_t x = 43; x <= 45; ++x) {
        auto* px = pixels.pixel(x, y);
        px[0] = 230;
        px[1] = 20;
        px[2] = 20;
        px[3] = 255;
      }
    }
    for (std::int32_t i = 0; i < 30; ++i) {
      auto* px = pixels.pixel(16 + i, 42 - i / 2);
      px[0] = 230;
      px[1] = 20;
      px[2] = 20;
      px[3] = 255;
    }
    return pixels;
  };
  const auto check_transparent_spatial_filter = [&](std::string_view identifier) {
    const auto before = make_transparent_red_stroke();
    auto after = before;
    registry.apply(identifier, after);
    int spread_pixels = 0;
    bool kept_clean_red = false;
    for (std::int32_t y = 0; y < after.height(); ++y) {
      for (std::int32_t x = 0; x < after.width(); ++x) {
        const auto* src = before.pixel(x, y);
        const auto* dst = after.pixel(x, y);
        if (src[3] == 0 && dst[3] > 8) {
          ++spread_pixels;
          kept_clean_red = kept_clean_red || (dst[0] > 180 && dst[1] < 80 && dst[2] < 80);
        }
      }
    }
    CHECK(spread_pixels > 0);
    CHECK(kept_clean_red);
  };
  check_transparent_spatial_filter("patchy.filters.box_blur");
  check_transparent_spatial_filter("patchy.filters.gaussian_blur");
  check_transparent_spatial_filter("patchy.filters.motion_blur");
  check_transparent_spatial_filter("patchy.filters.radial_blur");
  check_transparent_spatial_filter("patchy.filters.pixelate");
  auto transparent_clouds = solid_rgba(16, 16, 0, 0, 0, 0);
  registry.apply("patchy.filters.clouds", transparent_clouds);
  CHECK(transparent_clouds.pixel(0, 0)[3] == 255);
  CHECK(transparent_clouds.pixel(15, 15)[3] == 255);

  auto edge = solid_rgb(3, 3, 0, 0, 0);
  for (std::int32_t y = 0; y < edge.height(); ++y) {
    for (std::int32_t x = 1; x < edge.width(); ++x) {
      auto* px = edge.pixel(x, y);
      px[0] = 255;
      px[1] = 255;
      px[2] = 255;
    }
  }
  registry.apply("patchy.filters.edge_detect", edge);
  CHECK(edge.pixel(1, 1)[0] == 255);
  CHECK(edge.pixel(1, 1)[1] == 255);
  CHECK(edge.pixel(1, 1)[2] == 255);

  auto glowing = solid_rgb(3, 3, 0, 0, 0);
  for (std::int32_t y = 0; y < glowing.height(); ++y) {
    for (std::int32_t x = 1; x < glowing.width(); ++x) {
      auto* px = glowing.pixel(x, y);
      px[0] = 255;
      px[1] = 255;
      px[2] = 255;
    }
  }
  registry.apply("patchy.filters.glowing_edges", glowing);
  CHECK(glowing.pixel(1, 1)[0] > 0);
  CHECK(glowing.pixel(0, 1)[0] < glowing.pixel(1, 1)[0]);

  auto relief = solid_rgb(3, 3, 100, 110, 120);
  registry.apply("patchy.filters.emboss", relief);
  CHECK(relief.pixel(1, 1)[0] == 128);
  CHECK(relief.pixel(1, 1)[1] == 128);
  CHECK(relief.pixel(1, 1)[2] == 128);

  auto twirled = make_filter_document();
  const auto twirl_before = twirled.layers().front().pixels();
  registry.apply("patchy.filters.twirl", twirled.layers().front().pixels());
  const auto twirl_after_data = twirled.layers().front().pixels().data();
  const auto twirl_before_data = twirl_before.data();
  CHECK(!std::equal(twirl_after_data.begin(), twirl_after_data.end(), twirl_before_data.begin()));

  auto wave = patchy::PixelBuffer(64, 16, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < wave.height(); ++y) {
    for (std::int32_t x = 0; x < wave.width(); ++x) {
      auto* px = wave.pixel(x, y);
      px[0] = static_cast<std::uint8_t>(x * 3);
      px[1] = 0;
      px[2] = 0;
    }
  }
  const auto wave_before = wave.pixel(10, 12)[0];
  registry.apply("patchy.filters.wave", wave);
  CHECK(wave.pixel(10, 12)[0] > wave_before);

  auto pinch = patchy::PixelBuffer(33, 33, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < pinch.height(); ++y) {
    for (std::int32_t x = 0; x < pinch.width(); ++x) {
      auto* px = pinch.pixel(x, y);
      px[0] = static_cast<std::uint8_t>(x * 6);
      px[1] = 0;
      px[2] = 0;
    }
  }
  const auto pinch_before = pinch.pixel(20, 16)[0];
  registry.apply("patchy.filters.pinch_bloat", pinch);
  CHECK(pinch.pixel(20, 16)[0] < pinch_before);

  auto clouds = make_filter_document();
  registry.apply("patchy.filters.clouds", clouds.layers().front().pixels());
  const auto* cloud_a = clouds.layers().front().pixels().pixel(0, 0);
  const auto* cloud_b = clouds.layers().front().pixels().pixel(31, 23);
  CHECK(cloud_a[0] == cloud_a[1]);
  CHECK(cloud_a[1] == cloud_a[2]);
  CHECK(cloud_a[0] != cloud_b[0]);

  auto pixelated = make_filter_document();
  registry.apply("patchy.filters.pixelate", pixelated.layers().front().pixels());
  const auto* pixelated_px = pixelated.layers().front().pixels().pixel(0, 0);
  CHECK(pixelated_px[0] == 12);
  CHECK(pixelated_px[1] == 15);
  CHECK(pixelated_px[2] == 83);

  auto halftone = solid_rgb(24, 24, 128, 128, 128);
  registry.apply("patchy.filters.color_halftone", halftone);
  bool halftone_varied = false;
  const auto* halftone_first = halftone.pixel(0, 0);
  for (std::int32_t y = 0; y < halftone.height(); ++y) {
    for (std::int32_t x = 0; x < halftone.width(); ++x) {
      const auto* px = halftone.pixel(x, y);
      halftone_varied = halftone_varied || px[0] != halftone_first[0] || px[1] != halftone_first[1] ||
                        px[2] != halftone_first[2];
    }
  }
  CHECK(halftone_varied);

  auto grain_a = solid_rgb(2, 2, 128, 128, 128);
  auto grain_b = solid_rgb(2, 2, 128, 128, 128);
  registry.apply("patchy.filters.film_grain", grain_a);
  registry.apply("patchy.filters.film_grain", grain_b);
  bool grain_changed = false;
  for (std::int32_t y = 0; y < grain_a.height(); ++y) {
    for (std::int32_t x = 0; x < grain_a.width(); ++x) {
      const auto* a = grain_a.pixel(x, y);
      const auto* b = grain_b.pixel(x, y);
      for (std::uint16_t channel = 0; channel < 3; ++channel) {
        CHECK(a[channel] == b[channel]);
        grain_changed = grain_changed || a[channel] != 128;
      }
    }
  }
  CHECK(grain_changed);

  auto vignetted = solid_rgb(5, 5, 255, 255, 255);
  registry.apply("patchy.filters.vignette", vignetted);
  CHECK(vignetted.pixel(2, 2)[0] == 255);
  CHECK(vignetted.pixel(0, 0)[0] < 130);
}

void filter_catalog_defines_stable_named_contracts() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  using Category = patchy::FilterCategory;
  struct ExpectedFilter {
    const char* identifier;
    Category category;
    bool adjustment_only;
    std::vector<std::pair<const char*, std::int64_t>> defaults;
  };
  const std::vector<ExpectedFilter> expected = {
      {"patchy.filters.invert", Category::Adjustment, true, {{"amount", 100}}},
      {"patchy.filters.brightness_contrast", Category::Adjustment, true,
       {{"brightness", 0}, {"contrast", 0}}},
      {"patchy.filters.grayscale", Category::Adjustment, true, {{"amount", 100}}},
      {"patchy.filters.desaturate", Category::Adjustment, true, {{"amount", 100}}},
      {"patchy.filters.auto_contrast", Category::Adjustment, true, {{"amount", 100}}},
      {"patchy.filters.soft_glow", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.punchy_color", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.noir", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.cinematic_matte", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.vintage_fade", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.sepia", Category::PhotoLooks, false, {{"amount", 100}}},
      {"patchy.filters.threshold", Category::Adjustment, true, {{"threshold", 128}}},
      {"patchy.filters.posterize", Category::Adjustment, true, {{"levels", 4}}},
      {"patchy.filters.box_blur", Category::Blur, false, {{"radius", 1}}},
      {"patchy.filters.sharpen", Category::Sharpen, false, {{"amount", 100}}},
      {"patchy.filters.unsharp_mask", Category::Sharpen, false,
       {{"amount", 150}, {"radius", 2}, {"threshold", 8}}},
      {"patchy.filters.gaussian_blur", Category::Blur, false, {{"radius", 2}}},
      {"patchy.filters.motion_blur", Category::Blur, false, {{"angle", 0}, {"distance", 12}}},
      {"patchy.filters.radial_blur", Category::Blur, false, {{"amount", 35}, {"samples", 16}}},
      {"patchy.filters.edge_detect", Category::Stylize, false, {{"strength", 100}}},
      {"patchy.filters.emboss", Category::Stylize, false,
       {{"angle", 135}, {"height", 2}, {"amount", 100}}},
      {"patchy.filters.glowing_edges", Category::Stylize, false,
       {{"edge_width", 2}, {"brightness", 140}, {"smoothness", 2}}},
      {"patchy.filters.twirl", Category::Distort, false, {{"angle", 180}, {"radius", 100}}},
      {"patchy.filters.wave", Category::Distort, false,
       {{"amplitude", 12}, {"wavelength", 48}, {"phase", 0}}},
      {"patchy.filters.pinch_bloat", Category::Distort, false,
       {{"amount", 35}, {"radius", 100}}},
      {"patchy.filters.clouds", Category::Render, false,
       {{"scale", 96}, {"detail", 6}, {"contrast", 40}, {"seed", 1}}},
      {"patchy.filters.pixelate", Category::Pixelate, false, {{"block_size", 4}}},
      {"patchy.filters.color_halftone", Category::Pixelate, false,
       {{"cell_size", 10}, {"intensity", 75}, {"contrast", 60}}},
      {"patchy.filters.film_grain", Category::Noise, false, {{"amount", 50}}},
      {"patchy.filters.vignette", Category::PhotoLooks, false, {{"strength", 55}}},
  };

  const auto has_center_parameters = [](std::string_view identifier) {
    return identifier == "patchy.filters.radial_blur" ||
           identifier == "patchy.filters.twirl" ||
           identifier == "patchy.filters.pinch_bloat" ||
           identifier == "patchy.filters.vignette";
  };
  const auto expected_presentation = [](std::string_view identifier,
                                        std::string_view key) {
    using Presentation = patchy::FilterParameterPresentation;
    if (key == "center_x") {
      return Presentation::CenterXPercent;
    }
    if (key == "center_y") {
      return Presentation::CenterYPercent;
    }
    if (key == "angle" &&
        (identifier == "patchy.filters.motion_blur" ||
         identifier == "patchy.filters.emboss" ||
         identifier == "patchy.filters.twirl")) {
      return Presentation::Angle;
    }
    if (key == "radius" &&
        (identifier == "patchy.filters.twirl" ||
         identifier == "patchy.filters.pinch_bloat")) {
      return Presentation::EffectRadiusPercent;
    }
    if (identifier == "patchy.filters.wave") {
      if (key == "amplitude") {
        return Presentation::WaveAmplitude;
      }
      if (key == "wavelength") {
        return Presentation::WaveWavelength;
      }
      if (key == "phase") {
        return Presentation::WavePhase;
      }
    }
    return Presentation::Standard;
  };

  CHECK(registry.filters().size() == expected.size());
  std::unordered_set<std::string> spatial_parameters;
  for (std::size_t filter_index = 0; filter_index < expected.size(); ++filter_index) {
    const auto& actual = registry.filters()[filter_index];
    const auto& wanted = expected[filter_index];
    CHECK(actual.identifier == wanted.identifier);
    CHECK(actual.catalog.category == wanted.category);
    CHECK(actual.catalog.adjustment_only == wanted.adjustment_only);
    CHECK(actual.catalog.schema_version == 1);
    CHECK(static_cast<bool>(actual.catalog.execute));
    const auto center_count = has_center_parameters(actual.identifier) ? 2U : 0U;
    CHECK(actual.catalog.parameters.size() == wanted.defaults.size() + center_count);
    const auto invocation = registry.default_invocation(actual.identifier);
    CHECK(invocation.filter_id == actual.identifier);
    CHECK(invocation.schema_version == 1);
    for (std::size_t parameter_index = 0; parameter_index < wanted.defaults.size(); ++parameter_index) {
      const auto& parameter = actual.catalog.parameters[parameter_index];
      const auto& [key, default_value] = wanted.defaults[parameter_index];
      CHECK(parameter.key == key);
      CHECK(parameter.kind == patchy::FilterParameterKind::Integer);
      CHECK(parameter.display_name.size() > 0);
      CHECK(parameter.control_object_name.size() > 0);
      CHECK(parameter.minimum.has_value());
      CHECK(parameter.maximum.has_value());
      CHECK(parameter.step == 1.0);
      CHECK(std::get<std::int64_t>(parameter.default_value) == default_value);
      CHECK(std::get<std::int64_t>(invocation.parameters.at(key)) == default_value);
      CHECK(parameter.presentation ==
            expected_presentation(actual.identifier, parameter.key));
      CHECK(static_cast<double>(default_value) >= *parameter.minimum);
      CHECK(static_cast<double>(default_value) <= *parameter.maximum);
      if (parameter.spatial_scale == patchy::FilterSpatialScale::Pixels) {
        spatial_parameters.insert(actual.identifier + "/" + parameter.key);
        CHECK(parameter.unit == patchy::FilterParameterUnit::Pixels);
      }
    }
    if (center_count != 0U) {
      constexpr std::array center_keys{"center_x", "center_y"};
      constexpr std::array center_names{"filterCenterX", "filterCenterY"};
      for (std::size_t center_index = 0; center_index < center_keys.size();
           ++center_index) {
        const auto &parameter = actual.catalog.parameters[
            wanted.defaults.size() + center_index];
        CHECK(parameter.key == center_keys[center_index]);
        CHECK(parameter.control_object_name == center_names[center_index]);
        CHECK(parameter.kind == patchy::FilterParameterKind::Double);
        CHECK(std::get<double>(parameter.default_value) == 50.0);
        CHECK(parameter.minimum == 0.0);
        CHECK(parameter.maximum == 100.0);
        CHECK(parameter.step == 0.1);
        CHECK(parameter.unit == patchy::FilterParameterUnit::Percent);
        CHECK(parameter.spatial_scale == patchy::FilterSpatialScale::None);
        CHECK(parameter.presentation ==
              expected_presentation(actual.identifier, parameter.key));
        CHECK(std::get<double>(invocation.parameters.at(parameter.key)) ==
              50.0);
      }
    }
  }

  const std::unordered_set<std::string> expected_spatial = {
      "patchy.filters.box_blur/radius",          "patchy.filters.unsharp_mask/radius",
      "patchy.filters.gaussian_blur/radius",     "patchy.filters.motion_blur/distance",
      "patchy.filters.emboss/height",             "patchy.filters.glowing_edges/edge_width",
      "patchy.filters.glowing_edges/smoothness",  "patchy.filters.wave/amplitude",
      "patchy.filters.wave/wavelength",           "patchy.filters.clouds/scale",
      "patchy.filters.pixelate/block_size",        "patchy.filters.color_halftone/cell_size",
  };
  CHECK(spatial_parameters == expected_spatial);
}

void filter_invocations_normalize_scale_and_reject_bad_data() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  auto gaussian = registry.default_invocation("patchy.filters.gaussian_blur",
                                              patchy::RgbColor{1, 2, 3}, patchy::RgbColor{4, 5, 6});
  gaussian.parameters.erase("radius");
  gaussian.parameters["future_parameter"] = std::string("ignored");
  const auto normalized = registry.normalize(gaussian);
  CHECK(normalized.has_value());
  CHECK(normalized->parameters.size() == 1);
  CHECK(std::get<std::int64_t>(normalized->parameters.at("radius")) == 2);
  CHECK(normalized->foreground.red == 1);
  CHECK(normalized->background.blue == 6);

  gaussian.parameters["radius"] = std::int64_t{999};
  const auto clamped = registry.normalize(gaussian);
  CHECK(clamped.has_value());
  CHECK(std::get<std::int64_t>(clamped->parameters.at("radius")) == 12);
  gaussian.parameters["radius"] = 2.0;
  CHECK(!registry.supports(gaussian));
  gaussian.parameters["radius"] = std::int64_t{2};
  gaussian.schema_version = 2;
  CHECK(!registry.supports(gaussian));
  gaussian.schema_version = 1;
  gaussian.filter_id = "patchy.filters.missing";
  CHECK(!registry.supports(gaussian));

  auto wave = registry.default_invocation("patchy.filters.wave");
  const auto scaled_wave = registry.scale(wave, 0.25);
  CHECK(scaled_wave.has_value());
  CHECK(std::get<std::int64_t>(scaled_wave->parameters.at("amplitude")) == 3);
  CHECK(std::get<std::int64_t>(scaled_wave->parameters.at("wavelength")) == 12);
  CHECK(std::get<std::int64_t>(scaled_wave->parameters.at("phase")) == 0);
  auto twirl = registry.default_invocation("patchy.filters.twirl");
  const auto scaled_twirl = registry.scale(twirl, 0.25);
  CHECK(scaled_twirl.has_value());
  CHECK(std::get<std::int64_t>(scaled_twirl->parameters.at("radius")) == 100);
  CHECK(std::get<double>(scaled_twirl->parameters.at("center_x")) == 50.0);
  CHECK(std::get<double>(scaled_twirl->parameters.at("center_y")) == 50.0);
  CHECK(!registry.scale(twirl, 0.0).has_value());

  auto radial = registry.default_invocation("patchy.filters.radial_blur");
  radial.parameters["center_x"] = 17.5;
  radial.parameters["center_y"] = 82.5;
  const auto scaled_radial = registry.scale(radial, 0.125);
  CHECK(scaled_radial.has_value());
  CHECK(std::get<double>(scaled_radial->parameters.at("center_x")) == 17.5);
  CHECK(std::get<double>(scaled_radial->parameters.at("center_y")) == 82.5);
  radial.parameters.erase("center_x");
  const auto normalized_radial = registry.normalize(radial);
  CHECK(normalized_radial.has_value());
  CHECK(std::get<double>(normalized_radial->parameters.at("center_x")) == 50.0);
  radial.parameters["center_x"] = std::int64_t{25};
  CHECK(!registry.supports(radial));

  patchy::FilterCatalogMetadata custom_catalog;
  custom_catalog.schema_version = 1;
  custom_catalog.parameters = {
      patchy::FilterParameterDefinition{"real", "Real", "testReal", patchy::FilterParameterKind::Double,
                                        1.5, 0.0, 2.0, 0.1},
      patchy::FilterParameterDefinition{"flag", "Flag", "testFlag", patchy::FilterParameterKind::Boolean,
                                        true},
      patchy::FilterParameterDefinition{
          "option", "Option", "testOption", patchy::FilterParameterKind::Option, std::string("one"),
          std::nullopt, std::nullopt, std::nullopt, patchy::FilterParameterUnit::None,
          patchy::FilterSpatialScale::None,
          {patchy::FilterParameterOption{"one", "One"}, patchy::FilterParameterOption{"two", "Two"}}},
  };
  custom_catalog.execute = [](const patchy::FilterRegistry&, const patchy::FilterInvocation&,
                              patchy::PixelBuffer&, const patchy::FilterProgress*) {};
  registry.register_filter(
      {"test.filters.typed", "Typed", [](patchy::PixelBuffer&) {}, std::move(custom_catalog)});
  auto typed = registry.default_invocation("test.filters.typed");
  CHECK(registry.supports(typed));
  typed.parameters["real"] = 5.0;
  const auto typed_clamped = registry.normalize(typed);
  CHECK(typed_clamped.has_value());
  CHECK(std::get<double>(typed_clamped->parameters.at("real")) == 2.0);
  typed.parameters["real"] = std::int64_t{1};
  CHECK(!registry.supports(typed));
  typed = registry.default_invocation("test.filters.typed");
  typed.parameters["option"] = std::string("missing");
  CHECK(!registry.supports(typed));
  typed = registry.default_invocation("test.filters.typed");
  typed.parameters["flag"] = std::string("true");
  CHECK(!registry.supports(typed));
}

void filter_centers_preserve_defaults_move_effects_and_survive_padding() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  patchy::PixelBuffer source(17, 13, patchy::PixelFormat::rgba8());
  for (std::int32_t y = 0; y < source.height(); ++y) {
    for (std::int32_t x = 0; x < source.width(); ++x) {
      auto *pixel = source.pixel(x, y);
      pixel[0] = static_cast<std::uint8_t>((x * 31 + y * 7) % 256);
      pixel[1] = static_cast<std::uint8_t>((x * 11 + y * 29) % 256);
      pixel[2] = static_cast<std::uint8_t>((x * 19 + y * 13) % 256);
      pixel[3] = 255;
    }
  }
  const auto equal_pixels = [](const patchy::PixelBuffer &left,
                               const patchy::PixelBuffer &right) {
    return left.format() == right.format() && left.width() == right.width() &&
           left.height() == right.height() &&
           std::equal(left.data().begin(), left.data().end(),
                      right.data().begin());
  };

  // These three named defaults historically matched the legacy wrapper. The
  // newly appended 50/50 center parameters must not move that output.
  for (const auto *identifier : {"patchy.filters.radial_blur",
                                 "patchy.filters.twirl",
                                 "patchy.filters.pinch_bloat"}) {
    auto legacy = source;
    registry.apply(identifier, legacy);
    auto named = source;
    registry.apply(registry.default_invocation(identifier), named);
    CHECK(equal_pixels(legacy, named));
  }

  auto vignette_source = solid_rgb(9, 7, 255, 255, 255);
  registry.apply(registry.default_invocation("patchy.filters.vignette"),
                 vignette_source);
  CHECK(vignette_source.pixel(4, 3)[0] == 255);
  CHECK(vignette_source.pixel(0, 0)[0] == 115);

  for (const auto *identifier : {"patchy.filters.radial_blur",
                                 "patchy.filters.twirl",
                                 "patchy.filters.pinch_bloat",
                                 "patchy.filters.vignette"}) {
    auto centered = source;
    auto centered_invocation = registry.default_invocation(identifier);
    registry.apply(centered_invocation, centered);

    auto explicit_center = source;
    centered_invocation.parameters["center_x"] = 50.0;
    centered_invocation.parameters["center_y"] = 50.0;
    registry.apply(centered_invocation, explicit_center);
    CHECK(equal_pixels(centered, explicit_center));

    auto moved = source;
    auto moved_invocation = registry.default_invocation(identifier);
    moved_invocation.parameters["center_x"] = 25.0;
    moved_invocation.parameters["center_y"] = 75.0;
    registry.apply(moved_invocation, moved);
    CHECK(!equal_pixels(centered, moved));
    for (std::uint16_t channel = 0; channel < 4; ++channel) {
      CHECK(moved.pixel(4, 9)[channel] == source.pixel(4, 9)[channel]);
    }
  }

  // Radial Blur grows an RGBA buffer before execution. The center percentage
  // is relative to the unpadded source and must be remapped for that temporary
  // buffer, otherwise this stationary center pixel loses alpha after growth.
  patchy::PixelBuffer point_source(11, 11, patchy::PixelFormat::rgba8());
  point_source.clear(0);
  for (std::uint16_t channel = 0; channel < 4; ++channel) {
    point_source.pixel(2, 8)[channel] = 255;
  }
  auto off_center_radial =
      registry.default_invocation("patchy.filters.radial_blur");
  off_center_radial.parameters["center_x"] = 20.0;
  off_center_radial.parameters["center_y"] = 80.0;
  CHECK(registry.output_margin(off_center_radial, 11, 11) > 0);
  auto edge_center_radial =
      registry.default_invocation("patchy.filters.radial_blur");
  edge_center_radial.parameters["center_x"] = 0.0;
  edge_center_radial.parameters["center_y"] = 50.0;
  // The far corners of a 1024px layer sweep well beyond the old 256px safety
  // cap. Output growth must follow the actual sampled geometry so the halo is
  // not clipped before rendering.
  CHECK(registry.output_margin(edge_center_radial, 1024, 1024) > 600);
  const patchy::Rect point_bounds{100, 200, 11, 11};
  const auto confined =
      registry.render(off_center_radial, point_source, point_bounds, false);
  const auto expanded =
      registry.render(off_center_radial, point_source, point_bounds, true);
  const auto expanded_center_x = point_bounds.x + 2 - expanded.bounds.x;
  const auto expanded_center_y = point_bounds.y + 8 - expanded.bounds.y;
  CHECK(expanded_center_x >= 0 &&
        expanded_center_x < expanded.pixels.width());
  CHECK(expanded_center_y >= 0 &&
        expanded_center_y < expanded.pixels.height());
  for (std::uint16_t channel = 0; channel < 4; ++channel) {
    CHECK(expanded.pixels.pixel(expanded_center_x,
                                expanded_center_y)[channel] ==
          confined.pixels.pixel(2, 8)[channel]);
  }
}

void filter_named_engine_recipes_bounds_colors_and_legacy_stay_distinct() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  auto posterize_source = solid_rgb(1, 1, 50, 50, 50);
  auto legacy_posterize = posterize_source;
  registry.apply("patchy.filters.posterize", legacy_posterize);
  CHECK(legacy_posterize.pixel(0, 0)[0] == 0);
  auto named_posterize = posterize_source;
  registry.apply(registry.default_invocation("patchy.filters.posterize"), named_posterize);
  CHECK(named_posterize.pixel(0, 0)[0] == 85);

  patchy::PixelBuffer blur_source(5, 5, patchy::PixelFormat::rgb8());
  blur_source.pixel(2, 2)[0] = 255;
  blur_source.pixel(2, 2)[1] = 255;
  blur_source.pixel(2, 2)[2] = 255;
  auto legacy_gaussian = blur_source;
  registry.apply("patchy.filters.gaussian_blur", legacy_gaussian);
  CHECK(legacy_gaussian.pixel(2, 2)[0] == 36);
  auto named_gaussian = blur_source;
  registry.apply(registry.default_invocation("patchy.filters.gaussian_blur"), named_gaussian);
  CHECK(named_gaussian.pixel(2, 2)[0] == 28);

  auto clouds = registry.default_invocation("patchy.filters.clouds", patchy::RgbColor{240, 20, 10},
                                            patchy::RgbColor{5, 15, 230});
  auto cloud_pixels = solid_rgba(32, 24, 0, 0, 0, 0);
  registry.apply(clouds, cloud_pixels);
  bool saw_red_bias = false;
  bool saw_blue_bias = false;
  for (std::int32_t y = 0; y < cloud_pixels.height(); ++y) {
    for (std::int32_t x = 0; x < cloud_pixels.width(); ++x) {
      const auto* px = cloud_pixels.pixel(x, y);
      CHECK(px[3] == 255);
      saw_red_bias = saw_red_bias || px[0] > px[2];
      saw_blue_bias = saw_blue_bias || px[2] > px[0];
    }
  }
  CHECK(saw_red_bias);
  CHECK(saw_blue_bias);

  auto rgba_source = solid_rgba(24, 24, 220, 28, 24, 255);
  auto box = registry.default_invocation("patchy.filters.box_blur");
  box.parameters["radius"] = std::int64_t{4};
  CHECK(registry.output_margin(box, 24, 24) == 4);
  CHECK(registry.translation_invariant_support(box) == 4);
  const patchy::Rect source_bounds{10, 20, 24, 24};
  const auto grown = registry.render(box, rgba_source, source_bounds);
  CHECK(grown.bounds.x == 6);
  CHECK(grown.bounds.y == 16);
  CHECK(grown.bounds.width == 32);
  CHECK(grown.bounds.height == 32);
  CHECK(grown.pixels.width() == 32);
  const auto confined = registry.render(box, rgba_source, source_bounds, false);
  CHECK(confined.bounds.x == source_bounds.x);
  CHECK(confined.bounds.width == source_bounds.width);
  CHECK(confined.pixels.width() == rgba_source.width());
  auto motion = registry.default_invocation("patchy.filters.motion_blur");
  motion.parameters["distance"] = std::int64_t{12};
  CHECK(registry.translation_invariant_support(motion) == 13);
  CHECK(!registry.translation_invariant_support(
             registry.default_invocation("patchy.filters.clouds"))
             .has_value());

  const auto recipe_source = solid_rgb(4, 3, 20, 40, 80);
  const auto invert = registry.default_invocation("patchy.filters.invert");
  patchy::FilterRecipe twice{{patchy::FilterRecipeEntry{invert}, patchy::FilterRecipeEntry{invert}}};
  auto twice_pixels = recipe_source;
  registry.apply(twice, twice_pixels);
  CHECK(std::equal(twice_pixels.data().begin(), twice_pixels.data().end(), recipe_source.data().begin()));
  patchy::FilterRecipe disabled{{patchy::FilterRecipeEntry{invert, false}}};
  auto disabled_pixels = recipe_source;
  registry.apply(disabled, disabled_pixels);
  CHECK(std::equal(disabled_pixels.data().begin(), disabled_pixels.data().end(), recipe_source.data().begin()));
  patchy::FilterRecipe transparent{{patchy::FilterRecipeEntry{invert, true, 0.0}}};
  auto transparent_pixels = recipe_source;
  registry.apply(transparent, transparent_pixels);
  CHECK(std::equal(transparent_pixels.data().begin(), transparent_pixels.data().end(),
                   recipe_source.data().begin()));
  patchy::FilterRecipe multiply{{patchy::FilterRecipeEntry{invert, true, 0.5,
                                                           patchy::BlendMode::Multiply}}};
  auto multiply_pixels = recipe_source;
  registry.apply(multiply, multiply_pixels);
  CHECK(!std::equal(multiply_pixels.data().begin(), multiply_pixels.data().end(),
                    recipe_source.data().begin()));
  patchy::FilterRecipe pass_through{{patchy::FilterRecipeEntry{invert, true, 1.0,
                                                               patchy::BlendMode::PassThrough}}};
  CHECK(!registry.supports(pass_through));
  patchy::FilterRecipe bad_opacity{{patchy::FilterRecipeEntry{invert, true, 1.5}}};
  CHECK(!registry.supports(bad_opacity));

  bool saw_blur = false;
  patchy::FilterProgress progress{[&](int completed, int, patchy::FilterProgressStage stage) {
    saw_blur = saw_blur || stage == patchy::FilterProgressStage::Blurring;
    return completed < 2;
  }};
  bool cancelled = false;
  try {
    auto pixels = solid_rgb(32, 32, 80, 120, 160);
    registry.apply(registry.default_invocation("patchy.filters.gaussian_blur"), pixels, &progress);
  } catch (const patchy::FilterCancelled&) {
    cancelled = true;
  }
  CHECK(cancelled);
  CHECK(saw_blur);
}

void filter_recipe_opacity_interpolates_rgba_results() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);
  const auto invert = registry.default_invocation("patchy.filters.invert");

  // A replacement filter that preserves alpha must not inflate that alpha when
  // its recipe opacity is below 100%.
  auto equal_alpha = solid_rgba(1, 1, 20, 40, 80, 128);
  const patchy::FilterRecipe half_invert{
      {patchy::FilterRecipeEntry{invert, true, 0.5, patchy::BlendMode::Normal}}};
  registry.apply(half_invert, equal_alpha);
  const auto* equal_px = equal_alpha.pixel(0, 0);
  CHECK(equal_px[0] == 128);
  CHECK(equal_px[1] == 128);
  CHECK(equal_px[2] == 128);
  CHECK(equal_px[3] == 128);

  auto box = registry.default_invocation("patchy.filters.box_blur");
  box.parameters["radius"] = std::int64_t{2};
  const patchy::Rect bounds{10, 20, 7, 7};
  const auto opaque_red = solid_rgba(7, 7, 220, 28, 24, 255);
  const auto full_blur = registry.render(box, opaque_red, bounds);
  const patchy::FilterRecipe half_blur{
      {patchy::FilterRecipeEntry{box, true, 0.5, patchy::BlendMode::Normal}}};
  const auto faded_blur = registry.render(half_blur, opaque_red, bounds);
  CHECK(faded_blur.bounds.x == full_blur.bounds.x);
  CHECK(faded_blur.bounds.y == full_blur.bounds.y);
  CHECK(faded_blur.pixels.width() == full_blur.pixels.width());
  const auto halo_y = full_blur.pixels.height() / 2;
  const auto* full_halo = full_blur.pixels.pixel(0, halo_y);
  const auto* faded_halo = faded_blur.pixels.pixel(0, halo_y);
  CHECK(full_halo[3] > 0 && full_halo[3] < 255);
  constexpr std::uint64_t kOpacityScale = 65535U;
  constexpr std::uint64_t kHalfWeight = 32768U;
  const auto expected_halo_alpha = static_cast<std::uint8_t>(
      (static_cast<std::uint64_t>(full_halo[3]) * kHalfWeight + kOpacityScale / 2U) /
      kOpacityScale);
  CHECK(faded_halo[3] == expected_halo_alpha);
  CHECK(faded_halo[0] == full_halo[0]);
  CHECK(faded_halo[1] == full_halo[1]);
  CHECK(faded_halo[2] == full_halo[2]);

  // A non-Normal entry still keeps the filtered color on source-only expanded
  // pixels instead of blending that halo against transparent black.
  const patchy::FilterRecipe multiply_blur{
      {patchy::FilterRecipeEntry{box, true, 0.5, patchy::BlendMode::Multiply}}};
  const auto multiplied_blur = registry.render(multiply_blur, opaque_red, bounds);
  const auto* multiplied_halo = multiplied_blur.pixels.pixel(0, halo_y);
  CHECK(multiplied_halo[3] == expected_halo_alpha);
  CHECK(multiplied_halo[0] == full_halo[0]);
  CHECK(multiplied_halo[1] == full_halo[1]);
  CHECK(multiplied_halo[2] == full_halo[2]);

  // When the filter itself changes coverage, opacity interpolates toward that
  // replacement alpha rather than compositing it over the old coverage.
  patchy::PixelBuffer alpha_source(3, 1, patchy::PixelFormat::rgba8());
  alpha_source.clear(0);
  auto* center = alpha_source.pixel(1, 0);
  center[0] = 200;
  center[1] = 40;
  center[2] = 20;
  center[3] = 255;
  auto radius_one = registry.default_invocation("patchy.filters.box_blur");
  auto filtered_alpha = alpha_source;
  registry.apply(radius_one, filtered_alpha);
  CHECK(filtered_alpha.pixel(1, 0)[3] == 85);
  const patchy::FilterRecipe half_alpha{
      {patchy::FilterRecipeEntry{radius_one, true, 0.5, patchy::BlendMode::Normal}}};
  auto interpolated_alpha = alpha_source;
  registry.apply(half_alpha, interpolated_alpha);
  const auto* interpolated_center = interpolated_alpha.pixel(1, 0);
  CHECK(interpolated_center[0] == 200);
  CHECK(interpolated_center[1] == 40);
  CHECK(interpolated_center[2] == 20);
  CHECK(interpolated_center[3] == 170);
}

void filter_recipe_native_smart_filter_mapping_is_all_or_nothing() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);
  auto first = registry.default_invocation(
      "patchy.filters.gaussian_blur", patchy::RgbColor{1, 2, 3},
      patchy::RgbColor{4, 5, 6});
  first.parameters["radius"] = std::int64_t{3};
  auto second = first;
  second.parameters["radius"] = std::int64_t{9};
  const patchy::FilterRecipe recipe{{
      patchy::FilterRecipeEntry{first, true, 0.37,
                                patchy::BlendMode::Multiply},
      patchy::FilterRecipeEntry{second, false, 1.0,
                                patchy::BlendMode::Normal},
  }};
  const auto mapped =
      patchy::smart_filter_entries_from_recipe(recipe, registry);
  CHECK(mapped.has_value() && mapped->size() == 2U);
  CHECK((*mapped)[0].kind == patchy::SmartFilterKind::GaussianBlur);
  CHECK((*mapped)[0].enabled);
  CHECK(std::abs((*mapped)[0].opacity - 0.37) < 0.000001);
  CHECK((*mapped)[0].blend_mode == patchy::BlendMode::Multiply);
  CHECK((*mapped)[0].foreground.red == 1U);
  CHECK((*mapped)[0].background.blue == 6U);
  CHECK(std::abs(std::get<patchy::GaussianBlurSmartFilter>(
                     (*mapped)[0].parameters)
                     .radius_pixels -
                 3.0) < 0.000001);
  CHECK(!(*mapped)[1].enabled);
  CHECK(std::abs(std::get<patchy::GaussianBlurSmartFilter>(
                     (*mapped)[1].parameters)
                     .radius_pixels -
                 9.0) < 0.000001);

  auto mixed = recipe;
  mixed.entries.push_back(patchy::FilterRecipeEntry{
      registry.default_invocation("patchy.filters.sharpen"), false});
  CHECK(!patchy::smart_filter_entries_from_recipe(mixed, registry)
             .has_value());
  auto wrong_schema = recipe;
  wrong_schema.entries.front().invocation.schema_version = 2U;
  CHECK(!patchy::smart_filter_entries_from_recipe(wrong_schema, registry)
             .has_value());
  CHECK(!patchy::smart_filter_entries_from_recipe({}, registry).has_value());
}

void filter_recipe_scales_supports_validates_and_skips_zero_opacity() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);

  auto box = registry.default_invocation("patchy.filters.box_blur",
                                         patchy::RgbColor{1, 2, 3},
                                         patchy::RgbColor{4, 5, 6});
  box.parameters["radius"] = std::int64_t{4};
  auto twirl = registry.default_invocation("patchy.filters.twirl",
                                           patchy::RgbColor{7, 8, 9},
                                           patchy::RgbColor{10, 11, 12});
  twirl.parameters["angle"] = std::int64_t{270};
  twirl.parameters["radius"] = std::int64_t{80};
  twirl.parameters["center_x"] = 25.5;
  twirl.parameters["center_y"] = 75.5;
  const patchy::FilterRecipe recipe{{
      patchy::FilterRecipeEntry{box, false, 0.25,
                                patchy::BlendMode::Multiply},
      patchy::FilterRecipeEntry{twirl, true, 0.75,
                                patchy::BlendMode::Screen},
  }};
  const auto scaled = registry.scale(recipe, 0.5);
  CHECK(scaled.has_value());
  CHECK(scaled->entries.size() == 2);
  CHECK(!scaled->entries[0].enabled);
  CHECK(scaled->entries[0].opacity == 0.25);
  CHECK(scaled->entries[0].blend_mode == patchy::BlendMode::Multiply);
  CHECK(std::get<std::int64_t>(
            scaled->entries[0].invocation.parameters.at("radius")) == 2);
  CHECK(scaled->entries[0].invocation.foreground.red == 1);
  CHECK(scaled->entries[0].invocation.background.blue == 6);
  CHECK(scaled->entries[1].enabled);
  CHECK(scaled->entries[1].opacity == 0.75);
  CHECK(scaled->entries[1].blend_mode == patchy::BlendMode::Screen);
  CHECK(std::get<std::int64_t>(
            scaled->entries[1].invocation.parameters.at("angle")) == 270);
  CHECK(std::get<std::int64_t>(
            scaled->entries[1].invocation.parameters.at("radius")) == 80);
  CHECK(std::get<double>(
            scaled->entries[1].invocation.parameters.at("center_x")) == 25.5);
  CHECK(std::get<double>(
            scaled->entries[1].invocation.parameters.at("center_y")) == 75.5);
  CHECK(scaled->entries[1].invocation.foreground.green == 8);
  CHECK(scaled->entries[1].invocation.background.red == 10);
  CHECK(!registry.scale(recipe, 0.0).has_value());

  auto gaussian = registry.default_invocation("patchy.filters.gaussian_blur");
  gaussian.parameters["radius"] = std::int64_t{3};
  const auto sharpen =
      registry.default_invocation("patchy.filters.sharpen");
  auto vignette = registry.default_invocation("patchy.filters.vignette");
  patchy::FilterRecipe supported{{
      patchy::FilterRecipeEntry{box},
      patchy::FilterRecipeEntry{gaussian},
      patchy::FilterRecipeEntry{sharpen},
      patchy::FilterRecipeEntry{vignette, false},
  }};
  CHECK(registry.translation_invariant_support(supported) == 8);
  supported.entries.back().enabled = true;
  supported.entries.back().opacity = 0.0;
  CHECK(registry.translation_invariant_support(supported) == 8);
  supported.entries.back().opacity = 1.0;
  CHECK(!registry.translation_invariant_support(supported).has_value());
  CHECK(registry.translation_invariant_support(patchy::FilterRecipe{}) == 0);

  patchy::FilterCatalogMetadata maximum_support_metadata;
  maximum_support_metadata.execute =
      [](const patchy::FilterRegistry&, const patchy::FilterInvocation&,
         patchy::PixelBuffer&, const patchy::FilterProgress*) {};
  maximum_support_metadata.translation_support =
      [](const patchy::FilterInvocation&) -> std::optional<int> {
    return std::numeric_limits<int>::max();
  };
  registry.register_filter(
      {"test.filters.maximum_support", "Maximum Support",
       [](patchy::PixelBuffer&) {}, std::move(maximum_support_metadata)});
  const auto maximum_support =
      registry.default_invocation("test.filters.maximum_support");
  const patchy::FilterRecipe overflowing{{
      patchy::FilterRecipeEntry{maximum_support},
      patchy::FilterRecipeEntry{maximum_support},
  }};
  CHECK(!registry.translation_invariant_support(overflowing).has_value());

  for (const auto opacity :
       {-0.01, 1.01, std::numeric_limits<double>::infinity(),
        std::numeric_limits<double>::quiet_NaN()}) {
    const patchy::FilterRecipe invalid{
        {patchy::FilterRecipeEntry{box, true, opacity}}};
    CHECK(!registry.supports(invalid));
    CHECK(!registry.scale(invalid, 0.5).has_value());
    CHECK(!registry.translation_invariant_support(invalid).has_value());
  }
  const patchy::FilterRecipe pass_through{{patchy::FilterRecipeEntry{
      box, true, 1.0, patchy::BlendMode::PassThrough}}};
  CHECK(!registry.supports(pass_through));
  const patchy::FilterRecipe invalid_mode{{patchy::FilterRecipeEntry{
      box, true, 1.0, static_cast<patchy::BlendMode>(999)}}};
  CHECK(!registry.supports(invalid_mode));
  auto missing = box;
  missing.filter_id = "test.filters.missing";
  const patchy::FilterRecipe disabled_missing{
      {patchy::FilterRecipeEntry{missing, false}}};
  CHECK(!registry.supports(disabled_missing));
  CHECK(!registry.scale(disabled_missing, 0.5).has_value());

  int executions = 0;
  patchy::FilterCatalogMetadata counted_metadata;
  counted_metadata.execute =
      [&executions](const patchy::FilterRegistry&,
                    const patchy::FilterInvocation&, patchy::PixelBuffer& pixels,
                    const patchy::FilterProgress*) {
    ++executions;
    pixels.pixel(0, 0)[0] = 255;
  };
  counted_metadata.output_margin =
      [](const patchy::FilterInvocation&, std::int32_t,
         std::int32_t) { return 5; };
  counted_metadata.translation_support =
      [](const patchy::FilterInvocation&) -> std::optional<int> { return 2; };
  registry.register_filter({"test.filters.counted", "Counted",
                            [](patchy::PixelBuffer&) {},
                            std::move(counted_metadata)});
  const auto counted = registry.default_invocation("test.filters.counted");
  const patchy::FilterRecipe zero_opacity{
      {patchy::FilterRecipeEntry{counted, true, 0.0}}};
  auto source = solid_rgba(3, 2, 10, 20, 30, 255);
  const auto source_copy = source;
  int progress_calls = 0;
  const patchy::FilterProgress progress{
      [&progress_calls](int, int, patchy::FilterProgressStage) {
        ++progress_calls;
        return true;
      }};
  registry.apply(zero_opacity, source, &progress);
  CHECK(executions == 0);
  CHECK(progress_calls == 0);
  CHECK(std::equal(source.data().begin(), source.data().end(),
                   source_copy.data().begin()));
  const patchy::Rect source_bounds{13, 17, 3, 2};
  const auto rendered =
      registry.render(zero_opacity, source, source_bounds, true, &progress);
  CHECK(executions == 0);
  CHECK(progress_calls == 0);
  CHECK(rendered.bounds.x == source_bounds.x);
  CHECK(rendered.bounds.y == source_bounds.y);
  CHECK(rendered.bounds.width == source_bounds.width);
  CHECK(rendered.bounds.height == source_bounds.height);
  CHECK(std::equal(rendered.pixels.data().begin(),
                   rendered.pixels.data().end(), source.data().begin()));
}

void filter_recipe_order_and_bounds_match_explicit_execution() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);
  auto clouds = registry.default_invocation(
      "patchy.filters.clouds", patchy::RgbColor{240, 20, 10},
      patchy::RgbColor{5, 15, 230});
  auto box = registry.default_invocation("patchy.filters.box_blur");
  box.parameters["radius"] = std::int64_t{2};
  const auto source = solid_rgba(9, 7, 30, 70, 110, 200);
  const patchy::Rect bounds{40, 60, 9, 7};

  const auto first = registry.render(clouds, source, bounds);
  const auto explicit_result =
      registry.render(box, first.pixels, first.bounds);
  const patchy::FilterRecipe ordered{{patchy::FilterRecipeEntry{clouds},
                                      patchy::FilterRecipeEntry{box}}};
  const auto recipe_result = registry.render(ordered, source, bounds);
  CHECK(recipe_result.bounds.x == explicit_result.bounds.x);
  CHECK(recipe_result.bounds.y == explicit_result.bounds.y);
  CHECK(recipe_result.bounds.width == explicit_result.bounds.width);
  CHECK(recipe_result.bounds.height == explicit_result.bounds.height);
  CHECK(recipe_result.bounds.x == bounds.x - 2);
  CHECK(recipe_result.bounds.y == bounds.y - 2);
  CHECK(recipe_result.bounds.width == bounds.width + 4);
  CHECK(recipe_result.bounds.height == bounds.height + 4);
  CHECK(recipe_result.pixels.format() == explicit_result.pixels.format());
  CHECK(recipe_result.pixels.width() == explicit_result.pixels.width());
  CHECK(recipe_result.pixels.height() == explicit_result.pixels.height());
  CHECK(std::equal(recipe_result.pixels.data().begin(),
                   recipe_result.pixels.data().end(),
                   explicit_result.pixels.data().begin()));

  const patchy::FilterRecipe reversed{{patchy::FilterRecipeEntry{box},
                                       patchy::FilterRecipeEntry{clouds}}};
  const auto reversed_result = registry.render(reversed, source, bounds);
  CHECK(reversed_result.bounds.x == recipe_result.bounds.x);
  CHECK(reversed_result.bounds.y == recipe_result.bounds.y);
  CHECK(reversed_result.pixels.width() == recipe_result.pixels.width());
  CHECK(!std::equal(reversed_result.pixels.data().begin(),
                    reversed_result.pixels.data().end(),
                    recipe_result.pixels.data().begin()));
}

void filter_recipe_render_trace_records_every_entry_input_bounds() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);
  auto gaussian_two =
      registry.default_invocation("patchy.filters.gaussian_blur");
  gaussian_two.parameters["radius"] = std::int64_t{2};
  auto gaussian_six = gaussian_two;
  gaussian_six.parameters["radius"] = std::int64_t{6};
  auto gaussian_nine = gaussian_two;
  gaussian_nine.parameters["radius"] = std::int64_t{9};
  auto twirl = registry.default_invocation("patchy.filters.twirl");
  twirl.parameters["angle"] = std::int64_t{210};
  twirl.parameters["radius"] = std::int64_t{80};
  twirl.parameters["center_x"] = 35.0;
  twirl.parameters["center_y"] = 60.0;
  auto gaussian_three = gaussian_two;
  gaussian_three.parameters["radius"] = std::int64_t{3};

  const patchy::FilterRecipe recipe{{
      patchy::FilterRecipeEntry{gaussian_two},
      patchy::FilterRecipeEntry{gaussian_six, false},
      patchy::FilterRecipeEntry{gaussian_nine, true, 0.0},
      patchy::FilterRecipeEntry{twirl},
      patchy::FilterRecipeEntry{gaussian_three},
  }};
  const auto source = solid_rgba(17, 13, 45, 95, 155, 255);
  const patchy::Rect bounds{70, 90, source.width(), source.height()};
  patchy::FilterRecipeRenderTrace trace;
  const auto rendered =
      registry.render(recipe, source, bounds, true, nullptr, &trace);
  CHECK(trace.entry_input_bounds.size() == recipe.entries.size());

  const auto same_rect = [](patchy::Rect left, patchy::Rect right) {
    return left.x == right.x && left.y == right.y &&
           left.width == right.width && left.height == right.height;
  };
  patchy::FilterRenderResult expected{source, bounds};
  for (std::size_t index = 0; index < recipe.entries.size(); ++index) {
    CHECK(same_rect(trace.entry_input_bounds[index], expected.bounds));
    const auto& entry = recipe.entries[index];
    if (entry.enabled && entry.opacity > 0.0) {
      expected = registry.render(entry.invocation, expected.pixels,
                                 expected.bounds);
    }
  }
  CHECK(same_rect(rendered.bounds, expected.bounds));
  CHECK(rendered.pixels.format() == expected.pixels.format());
  CHECK(rendered.pixels.width() == expected.pixels.width());
  CHECK(rendered.pixels.height() == expected.pixels.height());
  CHECK(std::equal(rendered.pixels.data().begin(),
                   rendered.pixels.data().end(),
                   expected.pixels.data().begin()));
}

void filter_recipe_expansion_keeps_fully_transparent_bounds_stable() {
  patchy::FilterRegistry registry;
  patchy::register_builtin_filters(registry);
  patchy::PixelBuffer transparent(7, 5, patchy::PixelFormat::rgba8());
  transparent.clear(0);
  const patchy::Rect bounds{30, 40, 7, 5};
  auto box = registry.default_invocation("patchy.filters.box_blur");
  box.parameters["radius"] = std::int64_t{3};

  const auto single = registry.render(box, transparent, bounds);
  CHECK(single.bounds.x == bounds.x);
  CHECK(single.bounds.y == bounds.y);
  CHECK(single.bounds.width == bounds.width);
  CHECK(single.bounds.height == bounds.height);
  CHECK(single.pixels.width() == transparent.width());
  CHECK(single.pixels.height() == transparent.height());
  CHECK(std::equal(single.pixels.data().begin(), single.pixels.data().end(),
                   transparent.data().begin()));

  const patchy::FilterRecipe repeated{{patchy::FilterRecipeEntry{box},
                                       patchy::FilterRecipeEntry{box}}};
  const auto stacked = registry.render(repeated, transparent, bounds);
  CHECK(stacked.bounds.x == bounds.x);
  CHECK(stacked.bounds.y == bounds.y);
  CHECK(stacked.bounds.width == bounds.width);
  CHECK(stacked.bounds.height == bounds.height);
  CHECK(stacked.pixels.width() == transparent.width());
  CHECK(stacked.pixels.height() == transparent.height());
  CHECK(std::equal(stacked.pixels.data().begin(), stacked.pixels.data().end(),
                   transparent.data().begin()));

  // Recipe opacity uses a deterministic 16-bit fixed-point weight. A positive
  // value that quantizes to zero must also retain the input bounds; otherwise
  // an invisible blur would still grow the layer and create a no-op undo.
  const auto opaque = solid_rgba(7, 5, 35, 85, 145, 255);
  const patchy::FilterRecipe microscopic{{patchy::FilterRecipeEntry{
      box, true, 0.25 / 65535.0, patchy::BlendMode::Normal}}};
  const auto microscopic_result =
      registry.render(microscopic, opaque, bounds);
  CHECK(microscopic_result.bounds.x == bounds.x);
  CHECK(microscopic_result.bounds.y == bounds.y);
  CHECK(microscopic_result.bounds.width == bounds.width);
  CHECK(microscopic_result.bounds.height == bounds.height);
  CHECK(std::equal(microscopic_result.pixels.data().begin(),
                   microscopic_result.pixels.data().end(),
                   opaque.data().begin()));
}

void bmp_reader_rejects_invalid_headers() {
  CHECK(!patchy::bmp::DocumentIo::can_read({}));
  const std::vector<std::uint8_t> not_bmp{'N', 'O'};
  CHECK(!patchy::bmp::DocumentIo::can_read(not_bmp));

  bool short_bmp_rejected = false;
  try {
    const std::vector<std::uint8_t> short_bmp{'B', 'M'};
    (void)patchy::bmp::DocumentIo::read(short_bmp);
  } catch (const std::exception&) {
    short_bmp_rejected = true;
  }
  CHECK(short_bmp_rejected);

  const auto valid = indexed_bmp_fixture(2, 1, 1, {patchy::RgbColor{0, 0, 0}, patchy::RgbColor{255, 255, 255}},
                                         {1});
  CHECK(patchy::bmp::DocumentIo::can_read(valid));
  const auto document = patchy::bmp::DocumentIo::read(valid);
  CHECK(document.width() == 1);
  CHECK(document.height() == 1);
}

void bmp_indexed_reads_2_4_8_bit_palettes_and_rows() {
  const std::vector<patchy::RgbColor> palette{
      patchy::RgbColor{0, 0, 0}, patchy::RgbColor{220, 20, 30}, patchy::RgbColor{30, 210, 80},
      patchy::RgbColor{40, 70, 230}, patchy::RgbColor{250, 220, 20}, patchy::RgbColor{20, 200, 220},
      patchy::RgbColor{210, 40, 220}, patchy::RgbColor{255, 255, 255}};
  const std::vector<std::uint8_t> indices{0, 1, 2, 3, 0, 3, 2, 1, 0, 3};

  for (const auto bits : {std::uint16_t{2}, std::uint16_t{4}, std::uint16_t{8}}) {
    const auto fixture_palette_size = bits == 2 ? 4U : palette.size();
    const std::vector<patchy::RgbColor> fixture_palette(palette.begin(),
                                                        palette.begin() + static_cast<std::ptrdiff_t>(fixture_palette_size));
    const auto bytes = indexed_bmp_fixture(bits, 5, 2, fixture_palette, indices, bits == 4);
    const auto document = patchy::bmp::DocumentIo::read(bytes);
    CHECK(document.width() == 5);
    CHECK(document.height() == 2);
    CHECK(document.format() == patchy::PixelFormat::rgb8());
    CHECK(document.indexed_palette().has_value());
    CHECK(document.indexed_palette()->source_bit_depth == bits);
    CHECK(document.indexed_palette()->colors.size() == fixture_palette_size);
    CHECK(std::abs(document.print_settings().horizontal_ppi - 300.0) < 0.02);
    CHECK(std::abs(document.print_settings().vertical_ppi - 150.0) < 0.02);

    const auto& pixels = document.layers().front().pixels();
    for (std::int32_t y = 0; y < 2; ++y) {
      for (std::int32_t x = 0; x < 5; ++x) {
        const auto expected = fixture_palette[indices[static_cast<std::size_t>(y) * 5U + static_cast<std::size_t>(x)]];
        const auto* pixel = pixels.pixel(x, y);
        CHECK(pixel[0] == expected.red);
        CHECK(pixel[1] == expected.green);
        CHECK(pixel[2] == expected.blue);
      }
    }
  }
}

patchy::Document indexed_test_document(const std::vector<patchy::RgbColor>& colors, std::int32_t width) {
  const auto height = static_cast<std::int32_t>((colors.size() + static_cast<std::size_t>(width) - 1U) /
                                               static_cast<std::size_t>(width));
  patchy::Document document(width, height, patchy::PixelFormat::rgb8());
  patchy::PixelBuffer pixels(width, height, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < height; ++y) {
    for (std::int32_t x = 0; x < width; ++x) {
      const auto index = std::min<std::size_t>(static_cast<std::size_t>(y) * static_cast<std::size_t>(width) +
                                                   static_cast<std::size_t>(x),
                                               colors.size() - 1U);
      const auto color = colors[index];
      auto* pixel = pixels.pixel(x, y);
      pixel[0] = color.red;
      pixel[1] = color.green;
      pixel[2] = color.blue;
    }
  }
  document.add_pixel_layer("Indexed Source", std::move(pixels));
  return document;
}

void bmp_exact_indexed_writes_and_round_trips() {
  const std::vector<patchy::RgbColor> palette{patchy::RgbColor{0, 0, 0}, patchy::RgbColor{250, 10, 30},
                                              patchy::RgbColor{20, 220, 80}, patchy::RgbColor{40, 80, 240}};
  auto document = indexed_test_document({palette[2], palette[1], palette[3], palette[0], palette[1], palette[2]}, 3);
  document.print_settings().horizontal_ppi = 72.0;
  document.print_settings().vertical_ppi = 144.0;
  document.indexed_palette() = patchy::DocumentIndexedPalette{palette, 4};

  const auto bytes = patchy::bmp::DocumentIo::write(
      document, patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Indexed4, patchy::bmp::BmpPaletteMode::Exact, true});
  CHECK(read_u16_le_at(bytes, 28) == 4);
  CHECK(read_u32_le_at(bytes, 34) == 8);
  CHECK(read_u32_le_at(bytes, 46) == palette.size());
  CHECK(bytes[54] == palette[0].blue);
  CHECK(bytes[55] == palette[0].green);
  CHECK(bytes[56] == palette[0].red);

  const auto round_tripped = patchy::bmp::DocumentIo::read(bytes);
  CHECK(round_tripped.indexed_palette().has_value());
  CHECK(round_tripped.indexed_palette()->colors.size() == palette.size());
  CHECK(round_tripped.indexed_palette()->colors[1].red == palette[1].red);
  CHECK(std::abs(round_tripped.print_settings().horizontal_ppi - 72.0) < 0.02);
  CHECK(std::abs(round_tripped.print_settings().vertical_ppi - 144.0) < 0.02);
  const auto& source = document.layers().front().pixels();
  const auto& read = round_tripped.layers().front().pixels();
  CHECK(source.data().size() == read.data().size());
  CHECK(std::equal(source.data().begin(), source.data().end(), read.data().begin()));
}

void bmp_exact_indexed_fails_when_palette_overflows() {
  const std::vector<patchy::RgbColor> colors{patchy::RgbColor{0, 0, 0},    patchy::RgbColor{50, 0, 0},
                                             patchy::RgbColor{0, 50, 0},   patchy::RgbColor{0, 0, 50},
                                             patchy::RgbColor{80, 80, 80}};
  const auto document = indexed_test_document(colors, 5);

  bool failed = false;
  try {
    (void)patchy::bmp::DocumentIo::write(
        document,
        patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Indexed2, patchy::bmp::BmpPaletteMode::Exact, true});
  } catch (const std::exception&) {
    failed = true;
  }
  CHECK(failed);
  CHECK(document.layers().front().pixels().pixel(4, 0)[0] == 80);
}

void bmp_quantized_indexed_writes_deterministically() {
  std::vector<patchy::RgbColor> colors;
  for (int i = 0; i < 12; ++i) {
    colors.push_back(patchy::RgbColor{static_cast<std::uint8_t>(i * 19),
                                      static_cast<std::uint8_t>(255 - i * 13),
                                      static_cast<std::uint8_t>((i * 37) % 256)});
  }
  const auto document = indexed_test_document(colors, 4);
  const auto options =
      patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Indexed2, patchy::bmp::BmpPaletteMode::Quantize, true};
  const auto first = patchy::bmp::DocumentIo::write(document, options);
  const auto second = patchy::bmp::DocumentIo::write(document, options);
  CHECK(first == second);
  CHECK(read_u16_le_at(first, 28) == 2);
  CHECK(read_u32_le_at(first, 46) <= 4);
  const auto read = patchy::bmp::DocumentIo::read(first);
  CHECK(read.indexed_palette().has_value());
  CHECK(read.indexed_palette()->colors.size() <= 4);
  CHECK(read.width() == 4);
  CHECK(read.height() == 3);
}

void bmp_palette_file_export_uses_pal_and_bmp_palettes() {
  const auto pal_path = std::filesystem::path("test-palette.pal");
  {
    std::ofstream file(pal_path, std::ios::binary);
    file << "JASC-PAL\n0100\n4\n0 0 0\n255 0 0\n0 255 0\n0 0 255\n";
  }

  const auto document =
      indexed_test_document({patchy::RgbColor{240, 10, 10}, patchy::RgbColor{10, 240, 10},
                             patchy::RgbColor{10, 10, 240}, patchy::RgbColor{12, 12, 12}},
                            4);
  const auto pal_bytes = patchy::bmp::DocumentIo::write(
      document, patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Indexed4,
                                          patchy::bmp::BmpPaletteMode::PaletteFile, false, pal_path});
  CHECK(read_u16_le_at(pal_bytes, 28) == 4);
  CHECK(read_u32_le_at(pal_bytes, 46) == 4);
  const auto pal_read = patchy::bmp::DocumentIo::read(pal_bytes);
  CHECK(pal_read.indexed_palette().has_value());
  CHECK(pal_read.indexed_palette()->colors[1].red == 255);
  CHECK(pal_read.layers().front().pixels().pixel(0, 0)[0] == 255);
  CHECK(pal_read.layers().front().pixels().pixel(1, 0)[1] == 255);
  CHECK(pal_read.layers().front().pixels().pixel(2, 0)[2] == 255);
  std::filesystem::remove(pal_path);

  const auto bmp_palette_path = std::filesystem::path("test-palette-source.bmp");
  const auto bmp_palette = std::vector<patchy::RgbColor>{patchy::RgbColor{0, 0, 0}, patchy::RgbColor{255, 255, 0}};
  const auto bmp_palette_bytes = indexed_bmp_fixture(8, 1, 1, bmp_palette, {1});
  {
    std::ofstream file(bmp_palette_path, std::ios::binary);
    file.write(reinterpret_cast<const char*>(bmp_palette_bytes.data()),
               static_cast<std::streamsize>(bmp_palette_bytes.size()));
  }
  const auto bmp_bytes = patchy::bmp::DocumentIo::write(
      indexed_test_document({patchy::RgbColor{250, 250, 20}}, 1),
      patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Indexed8,
                                patchy::bmp::BmpPaletteMode::PaletteFile, false, bmp_palette_path});
  CHECK(read_u32_le_at(bmp_bytes, 46) == 2);
  const auto bmp_read = patchy::bmp::DocumentIo::read(bmp_bytes);
  CHECK(bmp_read.layers().front().pixels().pixel(0, 0)[0] == 255);
  CHECK(bmp_read.layers().front().pixels().pixel(0, 0)[1] == 255);
  CHECK(bmp_read.layers().front().pixels().pixel(0, 0)[2] == 0);
  std::filesystem::remove(bmp_palette_path);
}

void bmp_rgb24_and_rgba32_write_and_read() {
  patchy::Document document(2, 1, patchy::PixelFormat::rgba8());
  patchy::PixelBuffer pixels(2, 1, patchy::PixelFormat::rgba8());
  auto* left = pixels.pixel(0, 0);
  left[0] = 255;
  left[3] = 64;
  auto* right = pixels.pixel(1, 0);
  right[1] = 255;
  right[3] = 255;
  document.add_pixel_layer("Alpha", std::move(pixels));

  const auto rgba = patchy::bmp::DocumentIo::write(
      document, patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Rgba32, patchy::bmp::BmpPaletteMode::Exact, true});
  CHECK(read_u16_le_at(rgba, 28) == 32);
  CHECK(read_u32_le_at(rgba, 30) == 3);
  const auto rgba_read = patchy::bmp::DocumentIo::read(rgba);
  CHECK(rgba_read.format() == patchy::PixelFormat::rgba8());
  CHECK(rgba_read.layers().front().pixels().pixel(0, 0)[3] == 64);
  CHECK(rgba_read.layers().front().pixels().pixel(1, 0)[1] == 255);

  const auto rgb = patchy::bmp::DocumentIo::write(
      document, patchy::bmp::WriteOptions{patchy::bmp::BmpEncoding::Rgb24, patchy::bmp::BmpPaletteMode::Exact, true});
  CHECK(read_u16_le_at(rgb, 28) == 24);
  const auto rgb_read = patchy::bmp::DocumentIo::read(rgb);
  CHECK(rgb_read.format() == patchy::PixelFormat::rgb8());
  CHECK(rgb_read.layers().front().pixels().pixel(0, 0)[0] == 255);
  CHECK(rgb_read.layers().front().pixels().pixel(0, 0)[1] > 190);
  CHECK(rgb_read.layers().front().pixels().pixel(0, 0)[2] > 190);
}

void format_registry_finds_psd() {
  patchy::FormatRegistry registry;
  patchy::register_builtin_formats(registry);
  CHECK(registry.find_by_extension(".psd") != nullptr);
  CHECK(registry.find_by_extension("PSB") != nullptr);
  CHECK(registry.find_by_extension(".bmp") != nullptr);
}

patchy::PixelBuffer solid_rgba_square(std::int32_t size, std::uint8_t r, std::uint8_t g, std::uint8_t b,
                                      std::uint8_t a) {
  patchy::PixelBuffer pixels(size, size, patchy::PixelFormat::rgba8());
  for (std::int32_t y = 0; y < size; ++y) {
    for (std::int32_t x = 0; x < size; ++x) {
      auto* px = pixels.pixel(x, y);
      px[0] = r;
      px[1] = g;
      px[2] = b;
      px[3] = a;
    }
  }
  return pixels;
}

void ico_reads_multi_size_and_round_trips_named_layers() {
  patchy::Document document(32, 32, patchy::PixelFormat::rgba8());
  document.add_pixel_layer("32x32", solid_rgba_square(32, 20, 40, 200, 255));
  {
    patchy::Layer small_layer(document.allocate_layer_id(), "16x16", solid_rgba_square(16, 200, 30, 10, 255));
    small_layer.set_visible(false);
    document.add_layer(std::move(small_layer));
  }

  const auto bytes = patchy::ico::DocumentIo::write(document, patchy::ico::WriteOptions{{16, 32}, true, false, 0, 0});
  CHECK(patchy::ico::DocumentIo::can_read(bytes));

  std::vector<std::string> notices;
  const auto read_back = patchy::ico::DocumentIo::read(bytes, &notices);
  CHECK(read_back.width() == 32);
  CHECK(read_back.height() == 32);
  CHECK(read_back.layers().size() == 2);
  CHECK(read_back.layers()[0].name() == "16x16");
  CHECK(!read_back.layers()[0].visible());
  CHECK(read_back.layers()[1].name() == "32x32");
  CHECK(read_back.layers()[1].visible());
  // Exact-size layers are written verbatim, so both sizes survive byte-for-byte.
  const auto* small_px = read_back.layers()[0].pixels().pixel(3, 3);
  CHECK(small_px[0] == 200);
  CHECK(small_px[1] == 30);
  CHECK(small_px[2] == 10);
  CHECK(small_px[3] == 255);
  const auto* large_px = read_back.layers()[1].pixels().pixel(20, 20);
  CHECK(large_px[0] == 20);
  CHECK(large_px[1] == 40);
  CHECK(large_px[2] == 200);
  CHECK(!notices.empty());
}

void ico_transparent_pixels_round_trip_and_mask_fallback_applies() {
  patchy::Document document(8, 8, patchy::PixelFormat::rgba8());
  auto pixels = solid_rgba_square(8, 90, 120, 30, 255);
  pixels.pixel(0, 0)[3] = 0;
  pixels.pixel(7, 7)[3] = 0;
  document.add_pixel_layer("8x8", std::move(pixels));

  const auto bytes = patchy::ico::DocumentIo::write(document, patchy::ico::WriteOptions{{8}, true, false, 0, 0});
  const auto read_back = patchy::ico::DocumentIo::read(bytes);
  CHECK(read_back.layers().size() == 1);
  CHECK(read_back.layers()[0].pixels().pixel(0, 0)[3] == 0);
  CHECK(read_back.layers()[0].pixels().pixel(7, 7)[3] == 0);
  CHECK(read_back.layers()[0].pixels().pixel(4, 4)[3] == 255);

  // A 32-bit entry whose alpha channel is uniformly zero must fall back to the AND mask
  // (the classic real-world authoring bug) instead of importing fully transparent.
  auto broken = bytes;
  // Find the XOR pixel data: header 6 + entry 16 + BITMAPINFOHEADER 40, rows of 8 RGBA px.
  const std::size_t xor_offset = 6 + 16 + 40;
  for (std::size_t px = 0; px < 64; ++px) {
    broken[xor_offset + px * 4 + 3] = 0;
  }
  const auto masked = patchy::ico::DocumentIo::read(broken);
  CHECK(masked.layers()[0].pixels().pixel(4, 4)[3] == 255);
  CHECK(masked.layers()[0].pixels().pixel(0, 0)[3] == 0);
}

void cur_round_trips_hotspot() {
  patchy::Document document(32, 32, patchy::PixelFormat::rgba8());
  document.add_pixel_layer("32x32", solid_rgba_square(32, 255, 255, 255, 255));

  const auto bytes = patchy::ico::DocumentIo::write(document, patchy::ico::WriteOptions{{16, 32}, true, true, 10, 12});
  CHECK(bytes[2] == 2);  // ICONDIR type = cursor

  const auto read_back = patchy::ico::DocumentIo::read(bytes);
  CHECK(read_back.layers().size() == 2);
  const auto& largest = read_back.layers().back();
  const auto found = largest.metadata().find(patchy::ico::kLayerMetadataCursorHotspot);
  CHECK(found != largest.metadata().end());
  CHECK(found->second == "10,12");
  // The 16px entry scales the hotspot proportionally.
  const auto& small_layer = read_back.layers().front();
  const auto small_found = small_layer.metadata().find(patchy::ico::kLayerMetadataCursorHotspot);
  CHECK(small_found != small_layer.metadata().end());
  CHECK(small_found->second == "5,6");
}

void ico_writer_png_entry_for_256() {
  // A fake PNG codec exercises the container plumbing without Qt: the payload is the PNG
  // signature + LE dimensions + raw RGBA.
  patchy::ico::set_png_codec(
      [](std::span<const std::uint8_t> bytes) {
        patchy::ico::RgbaImage image;
        if (bytes.size() < 16) {
          return image;
        }
        image.width = static_cast<std::int32_t>(bytes[8] | (bytes[9] << 8U) | (bytes[10] << 16U) | (bytes[11] << 24U));
        image.height =
            static_cast<std::int32_t>(bytes[12] | (bytes[13] << 8U) | (bytes[14] << 16U) | (bytes[15] << 24U));
        image.rgba.assign(bytes.begin() + 16, bytes.end());
        return image;
      },
      [](const patchy::ico::RgbaImage& image) {
        std::vector<std::uint8_t> bytes = {0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A};
        for (const auto value : {image.width, image.height}) {
          bytes.push_back(static_cast<std::uint8_t>(value & 0xff));
          bytes.push_back(static_cast<std::uint8_t>((value >> 8) & 0xff));
          bytes.push_back(static_cast<std::uint8_t>((value >> 16) & 0xff));
          bytes.push_back(static_cast<std::uint8_t>((value >> 24) & 0xff));
        }
        bytes.insert(bytes.end(), image.rgba.begin(), image.rgba.end());
        return bytes;
      });

  patchy::Document document(256, 256, patchy::PixelFormat::rgba8());
  document.add_pixel_layer("256x256", solid_rgba_square(256, 10, 200, 100, 255));
  const auto bytes = patchy::ico::DocumentIo::write(document, patchy::ico::WriteOptions{{32, 256}, true, false, 0, 0});

  // Directory: the 256 entry stores width/height bytes as 0 and a PNG payload.
  const std::size_t second_entry = 6 + 16;
  CHECK(bytes[second_entry] == 0);
  CHECK(bytes[second_entry + 1] == 0);
  const auto payload_offset = static_cast<std::size_t>(bytes[second_entry + 12] | (bytes[second_entry + 13] << 8U) |
                                                       (bytes[second_entry + 14] << 16U) |
                                                       (bytes[second_entry + 15] << 24U));
  CHECK(bytes[payload_offset] == 0x89);
  CHECK(bytes[payload_offset + 1] == 0x50);

  const auto read_back = patchy::ico::DocumentIo::read(bytes);
  CHECK(read_back.width() == 256);
  CHECK(read_back.layers().back().name() == "256x256");
  const auto* px = read_back.layers().back().pixels().pixel(128, 128);
  CHECK(px[0] == 10);
  CHECK(px[1] == 200);
  CHECK(px[2] == 100);

  patchy::ico::set_png_codec(nullptr, nullptr);
}

void ico_reads_real_world_samples() {
  // Committed fixtures: pillow-* are Pillow-authored; cpython-py.ico (PSF-2.0) and
  // vscode-code.ico (MIT) are real-world multi-size icons (see NOTICE-THIRD-PARTY.md).
  // The core suite has no PNG decoder, so PNG-compressed entries are skipped with a notice
  // here; the UI suite re-reads these fixtures with the Qt codec installed.
  patchy::ico::set_png_codec(nullptr, nullptr);
  // pillow-multisize-png.ico is ALL PNG entries: without a decoder it must fail with a clear
  // message rather than open empty (the UI suite reads it fully with the Qt codec).
  bool all_png_rejected = false;
  try {
    (void)patchy::ico::DocumentIo::read_file(
        patchy::test::committed_format_fixture_path("ico", "pillow-multisize-png.ico"));
  } catch (const std::exception& error) {
    all_png_rejected = std::string(error.what()).find("no readable images") != std::string::npos;
  }
  CHECK(all_png_rejected);

  const std::array<const char*, 5> names = {"pillow-bmp32.ico", "pillow-indexed.ico", "pillow-cursor.cur",
                                            "cpython-py.ico", "vscode-code.ico"};
  for (const auto* name : names) {
    const auto path = patchy::test::committed_format_fixture_path("ico", name);
    CHECK(std::filesystem::exists(path));
    std::vector<std::string> notices;
    const auto document = patchy::ico::DocumentIo::read_file(path, &notices);
    CHECK(!document.layers().empty());
    CHECK(document.width() > 0);
    CHECK(document.height() > 0);
    for (const auto& layer : document.layers()) {
      CHECK(layer.pixels().width() > 0);
      CHECK(layer.pixels().height() > 0);
    }
  }

  const auto cursor =
      patchy::ico::DocumentIo::read_file(patchy::test::committed_format_fixture_path("ico", "pillow-cursor.cur"));
  const auto hotspot = cursor.layers().back().metadata().find(patchy::ico::kLayerMetadataCursorHotspot);
  CHECK(hotspot != cursor.layers().back().metadata().end());
  CHECK(hotspot->second == "7,9");

  const auto indexed =
      patchy::ico::DocumentIo::read_file(patchy::test::committed_format_fixture_path("ico", "pillow-indexed.ico"));
  CHECK(indexed.width() == 32);
  // The Pillow art is a green disc with a yellow inset square; (24, 24) is disc-only.
  const auto* disc = indexed.layers().back().pixels().pixel(24, 24);
  CHECK(disc[3] == 255);
  CHECK(disc[1] > disc[0]);
}

void tga_reads_types_1_2_9_10_and_origin_flags() {
  const auto header = [](std::uint8_t color_map_type, std::uint8_t image_type, std::uint16_t map_length,
                         std::uint8_t map_bits, std::uint16_t width, std::uint16_t height, std::uint8_t depth,
                         std::uint8_t descriptor) {
    std::vector<std::uint8_t> bytes = {0, color_map_type, image_type, 0, 0,
                                       static_cast<std::uint8_t>(map_length & 0xff),
                                       static_cast<std::uint8_t>(map_length >> 8U), map_bits, 0, 0, 0, 0,
                                       static_cast<std::uint8_t>(width & 0xff),
                                       static_cast<std::uint8_t>(width >> 8U),
                                       static_cast<std::uint8_t>(height & 0xff),
                                       static_cast<std::uint8_t>(height >> 8U), depth, descriptor};
    return bytes;
  };

  // Type 2 raw, default bottom-up origin: the FIRST file row is the BOTTOM image row.
  {
    auto bytes = header(0, 2, 0, 0, 2, 2, 24, 0);
    // bottom row: blue, green; top row: red, white (BGR order in the file)
    const std::uint8_t px[] = {255, 0, 0, /**/ 0, 255, 0, /**/ 0, 0, 255, /**/ 255, 255, 255};
    bytes.insert(bytes.end(), std::begin(px), std::end(px));
    const auto document = patchy::tga::DocumentIo::read(bytes);
    CHECK(document.layers().front().pixels().pixel(0, 0)[0] == 255);  // top-left red
    CHECK(document.layers().front().pixels().pixel(1, 1)[1] == 255);  // bottom-right green
    CHECK(document.layers().front().pixels().pixel(0, 1)[2] == 255);  // bottom-left blue
  }
  // Type 2 top-down + right-to-left: both axes mirror.
  {
    auto bytes = header(0, 2, 0, 0, 2, 1, 24, 0x30);
    const std::uint8_t px[] = {255, 0, 0, /**/ 0, 255, 0};  // file order: blue, green
    bytes.insert(bytes.end(), std::begin(px), std::end(px));
    const auto document = patchy::tga::DocumentIo::read(bytes);
    CHECK(document.layers().front().pixels().pixel(1, 0)[2] == 255);  // blue lands right
    CHECK(document.layers().front().pixels().pixel(0, 0)[1] == 255);  // green lands left
  }
  // Type 10 RLE: a 3-pixel run + 1 literal, top-down.
  {
    auto bytes = header(0, 10, 0, 0, 4, 1, 32, 0x28);
    const std::uint8_t packets[] = {0x82, 10, 20, 30, 255, /**/ 0x00, 40, 50, 60, 128};
    bytes.insert(bytes.end(), std::begin(packets), std::end(packets));
    const auto document = patchy::tga::DocumentIo::read(bytes);
    const auto& pixels = document.layers().front().pixels();
    CHECK(pixels.pixel(0, 0)[2] == 10);
    CHECK(pixels.pixel(2, 0)[2] == 10);
    CHECK(pixels.pixel(3, 0)[2] == 40);
    CHECK(pixels.pixel(3, 0)[3] == 128);
  }
  // Type 1 indexed with a 2-entry color map; the palette must reach indexed_palette().
  {
    auto bytes = header(1, 1, 2, 24, 2, 1, 8, 0x20);
    const std::uint8_t map[] = {0, 0, 200, /**/ 0, 180, 0};  // BGR entries: red-ish, green-ish
    bytes.insert(bytes.end(), std::begin(map), std::end(map));
    bytes.push_back(0);
    bytes.push_back(1);
    const auto document = patchy::tga::DocumentIo::read(bytes);
    CHECK(document.layers().front().pixels().pixel(0, 0)[0] == 200);
    CHECK(document.layers().front().pixels().pixel(1, 0)[1] == 180);
    CHECK(document.indexed_palette().has_value());
    CHECK(document.indexed_palette()->colors.size() == 2);
  }
  // Type 9 RLE indexed.
  {
    auto bytes = header(1, 9, 2, 24, 3, 1, 8, 0x20);
    const std::uint8_t map[] = {30, 30, 30, /**/ 250, 250, 250};
    bytes.insert(bytes.end(), std::begin(map), std::end(map));
    const std::uint8_t packets[] = {0x81, 1, /**/ 0x00, 0};  // run of two index-1, literal index-0
    bytes.insert(bytes.end(), std::begin(packets), std::end(packets));
    const auto document = patchy::tga::DocumentIo::read(bytes);
    CHECK(document.layers().front().pixels().pixel(0, 0)[0] == 250);
    CHECK(document.layers().front().pixels().pixel(1, 0)[0] == 250);
    CHECK(document.layers().front().pixels().pixel(2, 0)[0] == 30);
  }
  // 16-bit files are rejected with a clear message.
  {
    auto bytes = header(0, 2, 0, 0, 1, 1, 16, 0);
    bytes.push_back(0);
    bytes.push_back(0);
    bool rejected = false;
    try {
      (void)patchy::tga::DocumentIo::read(bytes);
    } catch (const std::exception& error) {
      rejected = std::string(error.what()).find("16-bit") != std::string::npos;
    }
    CHECK(rejected);
  }
}

void tga_writer_rle32_round_trips() {
  patchy::Document document(33, 7, patchy::PixelFormat::rgba8());
  patchy::PixelBuffer pixels(33, 7, patchy::PixelFormat::rgba8());
  for (std::int32_t y = 0; y < 7; ++y) {
    for (std::int32_t x = 0; x < 33; ++x) {
      auto* px = pixels.pixel(x, y);
      // Mix of long runs and per-pixel noise to exercise both packet kinds.
      if (y < 3) {
        px[0] = 200;
        px[1] = 100;
        px[2] = 50;
        px[3] = 255;
      } else {
        px[0] = static_cast<std::uint8_t>(x * 7);
        px[1] = static_cast<std::uint8_t>(y * 31);
        px[2] = static_cast<std::uint8_t>(x + y);
        px[3] = x % 5 == 0 ? 0 : 255;
      }
    }
  }
  document.add_pixel_layer("Art", pixels);

  const auto bytes = patchy::tga::DocumentIo::write(document);
  CHECK(patchy::tga::DocumentIo::can_read(bytes));
  const auto read_back = patchy::tga::DocumentIo::read(bytes);
  CHECK(read_back.width() == 33);
  CHECK(read_back.height() == 7);
  const auto& round = read_back.layers().front().pixels();
  for (std::int32_t y = 0; y < 7; ++y) {
    for (std::int32_t x = 0; x < 33; ++x) {
      const auto* expected = pixels.pixel(x, y);
      const auto* actual = round.pixel(x, y);
      CHECK(actual[3] == expected[3]);
      if (expected[3] == 0) {
        // The flatten composites fully transparent pixels away; their RGB is not preserved.
        continue;
      }
      CHECK(actual[0] == expected[0]);
      CHECK(actual[1] == expected[1]);
      CHECK(actual[2] == expected[2]);
    }
  }
}

void tga_palette_mode_writes_indexed() {
  patchy::Document document(8, 4, patchy::PixelFormat::rgb8());
  const auto* preset = patchy::find_builtin_palette_preset("gameboy");
  CHECK(preset != nullptr);
  patchy::DocumentPaletteEditing editing;
  editing.palette.colors.assign(preset->colors.begin(), preset->colors.end());
  document.palette_editing() = editing;

  patchy::PixelBuffer pixels(8, 4, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < 4; ++y) {
    for (std::int32_t x = 0; x < 8; ++x) {
      const auto& color = preset->colors[static_cast<std::size_t>(x % 4)];
      auto* px = pixels.pixel(x, y);
      px[0] = color.red;
      px[1] = color.green;
      px[2] = color.blue;
    }
  }
  document.add_pixel_layer("Pixels", std::move(pixels));

  const auto bytes = patchy::tga::DocumentIo::write(document);
  CHECK(bytes[2] == 1);  // image type 1 = raw indexed
  const auto read_back = patchy::tga::DocumentIo::read(bytes);
  CHECK(read_back.indexed_palette().has_value());
  CHECK(read_back.indexed_palette()->colors.size() == preset->colors.size());
  for (std::int32_t x = 0; x < 8; ++x) {
    const auto& expected = preset->colors[static_cast<std::size_t>(x % 4)];
    const auto* px = read_back.layers().front().pixels().pixel(x, 2);
    CHECK(px[0] == expected.red);
    CHECK(px[1] == expected.green);
    CHECK(px[2] == expected.blue);
  }
}

void tga_reads_real_world_samples() {
  const std::array<const char*, 5> names = {"pillow-rgb24-raw.tga", "pillow-rgb24-rle.tga", "pillow-rgba32-rle.tga",
                                            "pillow-indexed.tga", "pillow-gray.tga"};
  for (const auto* name : names) {
    const auto path = patchy::test::committed_format_fixture_path("tga", name);
    CHECK(std::filesystem::exists(path));
    const auto document = patchy::tga::DocumentIo::read_file(path);
    CHECK(document.width() == 48);
    CHECK(document.height() == 32);
    const auto& pixels = document.layers().front().pixels();
    // Red quadrant top-left, background top-right (identical Pillow art in every mode).
    const auto* red = pixels.pixel(5, 5);
    const auto* background = pixels.pixel(40, 5);
    const bool gray = std::string(name).find("gray") != std::string::npos;
    if (gray) {
      CHECK(pixels.pixel(5, 5)[0] == pixels.pixel(5, 5)[1]);
      CHECK(red[0] > background[0]);
    } else {
      CHECK(red[0] > 150);
      CHECK(red[1] < 100);
      CHECK(background[2] > background[0]);
    }
  }
  const auto indexed =
      patchy::tga::DocumentIo::read_file(patchy::test::committed_format_fixture_path("tga", "pillow-indexed.tga"));
  CHECK(indexed.indexed_palette().has_value());
  const auto rgba =
      patchy::tga::DocumentIo::read_file(patchy::test::committed_format_fixture_path("tga", "pillow-rgba32-rle.tga"));
  CHECK(rgba.layers().front().pixels().pixel(40, 28)[3] == 128);  // ellipse half-alpha survives
}

// Minimal spec-compliant GIF parser + LZW decoder used ONLY to validate Patchy's encoder
// with no external dependencies (Qt's qgif and Pillow provide the real-world checks).
struct DecodedGif {
  std::int32_t width{0};
  std::int32_t height{0};
  std::vector<patchy::RgbColor> palette;
  int transparent_index{-1};
  std::vector<std::uint8_t> indexes;
};

DecodedGif reference_decode_gif(std::span<const std::uint8_t> bytes) {
  DecodedGif result;
  std::size_t pos = 0;
  const auto u8 = [&] { return bytes[pos++]; };
  const auto u16 = [&] {
    const auto value = static_cast<std::uint16_t>(bytes[pos] | (bytes[pos + 1] << 8U));
    pos += 2;
    return value;
  };
  CHECK(bytes.size() > 13);
  CHECK(std::equal(bytes.begin(), bytes.begin() + 6, reinterpret_cast<const std::uint8_t*>("GIF89a")));
  pos = 6;
  result.width = u16();
  result.height = u16();
  const auto packed = u8();
  u8();  // background index
  u8();  // aspect
  CHECK((packed & 0x80U) != 0);
  const auto table_entries = std::size_t{1} << ((packed & 0x07U) + 1U);
  for (std::size_t i = 0; i < table_entries; ++i) {
    const auto r = u8();
    const auto g = u8();
    const auto b = u8();
    result.palette.push_back(patchy::RgbColor{r, g, b});
  }

  std::vector<std::uint8_t> data;
  int min_code_size = 0;
  while (pos < bytes.size()) {
    const auto block = u8();
    if (block == 0x3b) {
      break;
    }
    if (block == 0x21) {
      const auto label = u8();
      if (label == 0xf9) {
        const auto size = u8();
        CHECK(size == 4);
        const auto gce_packed = u8();
        u16();  // delay
        const auto transparent = u8();
        if ((gce_packed & 0x01U) != 0) {
          result.transparent_index = transparent;
        }
        CHECK(u8() == 0);
      } else {
        for (auto size = u8(); size != 0; size = u8()) {
          pos += size;
        }
      }
      continue;
    }
    CHECK(block == 0x2c);
    u16();
    u16();
    CHECK(u16() == result.width);
    CHECK(u16() == result.height);
    CHECK(u8() == 0);  // no local table, not interlaced
    min_code_size = u8();
    for (auto size = u8(); size != 0; size = u8()) {
      data.insert(data.end(), bytes.begin() + static_cast<std::ptrdiff_t>(pos),
                  bytes.begin() + static_cast<std::ptrdiff_t>(pos + size));
      pos += size;
    }
  }

  // LZW decode.
  const auto clear_code = 1U << min_code_size;
  const auto end_code = clear_code + 1U;
  std::array<std::uint16_t, 4096> prefix{};
  std::array<std::uint8_t, 4096> suffix{};
  std::uint32_t next = clear_code + 2;
  int width_bits = min_code_size + 1;
  std::uint32_t bit_pos = 0;
  const auto read_code = [&]() -> std::uint32_t {
    std::uint32_t code = 0;
    for (int bit = 0; bit < width_bits; ++bit) {
      const auto byte_index = (bit_pos + static_cast<std::uint32_t>(bit)) / 8U;
      const auto bit_index = (bit_pos + static_cast<std::uint32_t>(bit)) % 8U;
      CHECK(byte_index < data.size());
      code |= static_cast<std::uint32_t>((data[byte_index] >> bit_index) & 1U) << bit;
    }
    bit_pos += static_cast<std::uint32_t>(width_bits);
    return code;
  };
  const auto expand = [&](std::uint32_t code, std::vector<std::uint8_t>& out) {
    std::vector<std::uint8_t> reversed;
    while (code >= clear_code + 2) {
      reversed.push_back(suffix[code]);
      code = prefix[code];
    }
    reversed.push_back(static_cast<std::uint8_t>(code));
    out.insert(out.end(), reversed.rbegin(), reversed.rend());
  };
  const auto first_symbol = [&](std::uint32_t code) {
    while (code >= clear_code + 2) {
      code = prefix[code];
    }
    return static_cast<std::uint8_t>(code);
  };
  std::int64_t prev = -1;
  while (true) {
    const auto code = read_code();
    if (code == clear_code) {
      next = clear_code + 2;
      width_bits = min_code_size + 1;
      prev = -1;
      continue;
    }
    if (code == end_code) {
      break;
    }
    if (prev < 0) {
      CHECK(code < clear_code);
      result.indexes.push_back(static_cast<std::uint8_t>(code));
      prev = static_cast<std::int64_t>(code);
      continue;
    }
    if (code < next) {
      expand(code, result.indexes);
      prefix[next] = static_cast<std::uint16_t>(prev);
      suffix[next] = first_symbol(code);
    } else {
      CHECK(code == next);
      prefix[next] = static_cast<std::uint16_t>(prev);
      suffix[next] = first_symbol(static_cast<std::uint32_t>(prev));
      expand(code, result.indexes);
    }
    ++next;
    if (next == (1U << width_bits) && width_bits < 12) {
      ++width_bits;
    }
    prev = static_cast<std::int64_t>(code);
  }
  return result;
}

void gif_lzw_round_trips_through_reference_decoder() {
  // A pattern with long runs, noise, and >256 dictionary entries so the code width grows.
  const std::int32_t width = 101;
  const std::int32_t height = 53;
  std::vector<patchy::RgbColor> palette;
  for (int i = 0; i < 200; ++i) {
    palette.push_back(patchy::RgbColor{static_cast<std::uint8_t>(i), static_cast<std::uint8_t>(255 - i),
                                       static_cast<std::uint8_t>(i * 3)});
  }
  std::vector<std::uint8_t> indexes(static_cast<std::size_t>(width) * static_cast<std::size_t>(height));
  std::uint64_t state = 0x243F6A8885A308D3ULL;
  for (std::size_t i = 0; i < indexes.size(); ++i) {
    if ((i / 97) % 2 == 0) {
      indexes[i] = static_cast<std::uint8_t>((i / 13) % palette.size());
    } else {
      state = state * 6364136223846793005ULL + 1442695040888963407ULL;
      indexes[i] = static_cast<std::uint8_t>((state >> 33U) % palette.size());
    }
  }

  const auto bytes = patchy::gif::encode(width, height, palette, indexes, 5);
  const auto decoded = reference_decode_gif(bytes);
  CHECK(decoded.width == width);
  CHECK(decoded.height == height);
  CHECK(decoded.transparent_index == 5);
  CHECK(decoded.indexes == indexes);
  CHECK(decoded.palette.size() >= palette.size());
  for (std::size_t i = 0; i < palette.size(); ++i) {
    CHECK(decoded.palette[i].red == palette[i].red);
    CHECK(decoded.palette[i].green == palette[i].green);
    CHECK(decoded.palette[i].blue == palette[i].blue);
  }
}

void gif_encoder_bytes_are_stable() {
  // Cross-platform byte-identical rule: the exact encoder output is pinned by an FNV-1a
  // hash. A change here means the GIF bytes changed — re-pin only for deliberate encoder
  // changes (the failure output prints the new hash).
  std::vector<patchy::RgbColor> palette = {{0, 0, 0}, {255, 255, 255}, {200, 30, 40}, {40, 60, 200}};
  std::vector<std::uint8_t> indexes;
  for (int i = 0; i < 64; ++i) {
    indexes.push_back(static_cast<std::uint8_t>((i / 3) % 4));
  }
  const auto bytes = patchy::gif::encode(8, 8, palette, indexes, 3);
  std::uint64_t hash = 1469598103934665603ULL;
  for (const auto byte : bytes) {
    hash ^= byte;
    hash *= 1099511628211ULL;
  }
  constexpr std::uint64_t kExpected = 0x67535dc068a89baaULL;
  if (hash != kExpected) {
    std::cout << "gif encoder hash: 0x" << std::hex << hash << std::dec << " size " << bytes.size() << "\n";
  }
  CHECK(hash == kExpected);

  const auto decoded = reference_decode_gif(bytes);
  CHECK(decoded.indexes == indexes);
}

void gif_document_write_quantizes_and_round_trips() {
  // RGB document: exact colors fit, so quantization must preserve them; transparency
  // reserves one slot.
  patchy::Document document(16, 8, patchy::PixelFormat::rgba8());
  patchy::PixelBuffer pixels(16, 8, patchy::PixelFormat::rgba8());
  const std::array<patchy::RgbColor, 3> colors = {{{10, 200, 50}, {240, 240, 240}, {60, 60, 220}}};
  for (std::int32_t y = 0; y < 8; ++y) {
    for (std::int32_t x = 0; x < 16; ++x) {
      auto* px = pixels.pixel(x, y);
      if (x < 2) {
        px[3] = 0;
        continue;
      }
      const auto& color = colors[static_cast<std::size_t>(x % 3)];
      px[0] = color.red;
      px[1] = color.green;
      px[2] = color.blue;
      px[3] = 255;
    }
  }
  document.add_pixel_layer("Art", std::move(pixels));

  const auto bytes = patchy::gif::write(document);
  const auto decoded = reference_decode_gif(bytes);
  CHECK(decoded.width == 16);
  CHECK(decoded.height == 8);
  CHECK(decoded.transparent_index >= 0);
  // Transparent pixels map to the transparent slot; opaque ones keep their exact color.
  CHECK(decoded.indexes[0] == static_cast<std::uint8_t>(decoded.transparent_index));
  const auto& c5 = decoded.palette[decoded.indexes[5]];
  CHECK(c5.red == colors[5 % 3].red);
  CHECK(c5.green == colors[5 % 3].green);
  CHECK(c5.blue == colors[5 % 3].blue);
}

void aseprite_imports_layers_groups_and_palette() {
  // Fixture authored by Aseprite 1.3.17 itself (scratch script; see the fixture comment in
  // NOTICE-THIRD-PARTY.md): Base, group "Props" holding half-opacity Multiply "Star" at
  // (5,6), hidden "Hidden", and "Weird" with the unsupported Exclusion blend.
  std::vector<std::string> notices;
  const auto document = patchy::aseprite::DocumentIo::read_file(
      patchy::test::committed_format_fixture_path("aseprite", "aseprite-layered.aseprite"), &notices);
  CHECK(document.width() == 32);
  CHECK(document.height() == 24);
  CHECK(document.layers().size() == 4);

  const auto& base = document.layers()[0];
  CHECK(base.name() == "Base");
  CHECK(base.pixels().pixel(3, 3)[2] == 200);

  // An RGB-mode file must NOT adopt its palette chunk (Aseprite pads a 256-black legacy
  // palette into RGB files; adopting it dragged documents into an all-black palette mode).
  CHECK(!document.indexed_palette().has_value());

  const auto& group = document.layers()[1];
  CHECK(group.kind() == patchy::LayerKind::Group);
  CHECK(group.name() == "Props");
  // Header flag bit 2 is unset, so the group chunk's opacity byte (0 in this file!) is
  // meaningless and the group must render at full opacity with Normal blend.
  CHECK(group.opacity() == 1.0F);
  CHECK(group.blend_mode() == patchy::BlendMode::Normal);
  CHECK(group.children().size() == 1);
  const auto& star = group.children()[0];
  CHECK(star.name() == "Star");
  CHECK(star.blend_mode() == patchy::BlendMode::Multiply);
  CHECK(star.bounds().x == 5);
  CHECK(star.bounds().y == 6);
  CHECK(star.opacity() > 0.45F);
  CHECK(star.opacity() < 0.55F);
  CHECK(star.pixels().pixel(0, 0)[0] == 200);

  CHECK(!document.layers()[2].visible());
  CHECK(document.layers()[3].name() == "Weird");
  // Exclusion is a supported blend mode now (July 2026), so no fallback notice appears.
  CHECK(document.layers()[3].blend_mode() == patchy::BlendMode::Exclusion);
  for (const auto& notice : notices) {
    CHECK(notice.find("Weird") == std::string::npos);
  }

  // The composite must show the group's child: Star multiplies red over blue at 50%, so
  // the star area is a dark blue clearly below the base color (this was the group-opacity
  // regression: the group imported at opacity 0 and Star vanished).
  const auto flattened = patchy::flatten_document_rgba8(document);
  const auto* base_px = flattened.pixel(2, 2);
  CHECK(base_px[0] == 10);
  CHECK(base_px[1] == 20);
  CHECK(base_px[2] == 200);
  const auto* star_px = flattened.pixel(7, 8);
  CHECK(star_px[2] < 160);  // multiplied down from 200
  CHECK(star_px[2] > 60);   // but not black: 50% layer opacity keeps half the base
  // The Exclusion layer renders for real: red over blue gives the magenta Aseprite shows.
  const auto* weird_px = flattened.pixel(22, 12);
  CHECK(weird_px[0] == 194);
  CHECK(weird_px[1] == 54);
  CHECK(weird_px[2] == 178);
}

void aseprite_blend_modes_match_aseprite_render() {
  // Fixture authored in Aseprite 1.3.17: base (10,20,200) with six 4x4 (200,40,40) squares
  // using Exclusion / Hue / Color / Addition / Subtract / Divide. The expected values are
  // Aseprite's own flattened render (committed as aseprite-blend-modes-reference.png);
  // the non-separable modes tolerate 1/255 of double-rounding drift.
  const auto document = patchy::aseprite::DocumentIo::read_file(
      patchy::test::committed_format_fixture_path("aseprite", "aseprite-blend-modes.aseprite"));
  CHECK(document.width() == 24);
  CHECK(document.layers().size() == 7);
  const auto flattened = patchy::flatten_document_rgba8(document);

  struct ExpectedSquare {
    patchy::BlendMode mode;
    std::uint8_t r;
    std::uint8_t g;
    std::uint8_t b;
    int tolerance;
  };
  const std::array<ExpectedSquare, 6> expected = {{
      {patchy::BlendMode::Exclusion, 194, 54, 178, 0},
      {patchy::BlendMode::Hue, 122, 0, 0, 1},
      {patchy::BlendMode::Color, 122, 0, 0, 1},
      {patchy::BlendMode::LinearDodge, 210, 60, 240, 0},
      {patchy::BlendMode::Subtract, 0, 0, 160, 0},
      {patchy::BlendMode::Divide, 13, 128, 255, 0},
  }};
  for (std::size_t index = 0; index < expected.size(); ++index) {
    const auto& square = expected[index];
    CHECK(document.layers()[index + 1].blend_mode() == square.mode);
    const auto* px = flattened.pixel(static_cast<std::int32_t>(index) * 4 + 2, 2);
    CHECK(std::abs(static_cast<int>(px[0]) - static_cast<int>(square.r)) <= square.tolerance);
    CHECK(std::abs(static_cast<int>(px[1]) - static_cast<int>(square.g)) <= square.tolerance);
    CHECK(std::abs(static_cast<int>(px[2]) - static_cast<int>(square.b)) <= square.tolerance);
  }

  // Writer round trip: every new mode survives Patchy's own .aseprite writer.
  const auto rewritten = patchy::aseprite::DocumentIo::read(patchy::aseprite::DocumentIo::write(document));
  for (std::size_t index = 0; index < expected.size(); ++index) {
    CHECK(rewritten.layers()[index + 1].blend_mode() == expected[index].mode);
  }
}

void psd_round_trips_new_blend_modes() {
  patchy::Document document(4, 4, patchy::PixelFormat::rgb8());
  document.add_pixel_layer("Base", solid_rgb(4, 4, 10, 20, 200));
  const std::array<patchy::BlendMode, 6> modes = {patchy::BlendMode::Exclusion,   patchy::BlendMode::Hue,
                                                  patchy::BlendMode::Color,       patchy::BlendMode::LinearDodge,
                                                  patchy::BlendMode::Subtract,    patchy::BlendMode::Divide};
  for (const auto mode : modes) {
    auto& layer = document.add_pixel_layer("Layer", solid_rgba(4, 4, 200, 40, 40, 255));
    layer.set_blend_mode(mode);
  }
  const auto bytes = patchy::psd::DocumentIo::write_layered_rgb8(document);
  const auto read_back = patchy::psd::DocumentIo::read(bytes, patchy::psd::ReadOptions{true, false, true});
  CHECK(read_back.layers().size() == modes.size() + 1);
  for (std::size_t index = 0; index < modes.size(); ++index) {
    CHECK(read_back.layers()[index + 1].blend_mode() == modes[index]);
  }
}

void aseprite_indexed_transparent_index() {
  std::vector<std::string> notices;
  const auto document = patchy::aseprite::DocumentIo::read_file(
      patchy::test::committed_format_fixture_path("aseprite", "aseprite-indexed-frames.aseprite"), &notices);
  CHECK(document.width() == 16);
  CHECK(document.height() == 12);
  CHECK(document.indexed_palette().has_value());
  CHECK(document.indexed_palette()->colors.size() == 4);
  const auto& pixels = document.layers().front().pixels();
  CHECK(pixels.pixel(0, 0)[3] == 0);  // transparent index
  CHECK(pixels.pixel(1, 0)[0] == 200);
  CHECK(pixels.pixel(8, 0)[2] == 200);
  bool noted_frames = false;
  for (const auto& notice : notices) {
    noted_frames = noted_frames || notice.find("first frame") != std::string::npos;
  }
  CHECK(noted_frames);
}

void aseprite_rejects_adobe_swatch_ase() {
  const std::vector<std::uint8_t> swatch = {'A', 'S', 'E', 'F', 0, 1, 0, 0};
  bool rejected = false;
  try {
    (void)patchy::aseprite::DocumentIo::read(swatch);
  } catch (const std::exception& error) {
    rejected = std::string(error.what()).find("Adobe swatch") != std::string::npos;
  }
  CHECK(rejected);
  CHECK(!patchy::aseprite::sniff(swatch));
}

void aseprite_write_read_round_trips_layers_and_palette() {
  patchy::Document document(20, 20, patchy::PixelFormat::rgba8());
  document.add_pixel_layer("Backdrop", solid_rgba_square(20, 30, 60, 90, 255));
  // add_pixel_layer requires full-canvas dimensions; shrink via a hand-built layer.
  {
    patchy::Layer sprite_layer(document.allocate_layer_id(), "Sprite", solid_rgba_square(6, 220, 50, 40, 255));
    sprite_layer.set_bounds(patchy::Rect{7, 3, 6, 6});
    sprite_layer.set_blend_mode(patchy::BlendMode::Multiply);
    sprite_layer.set_opacity(0.5F);
    document.add_layer(std::move(sprite_layer));
  }
  {
    patchy::Layer group(document.allocate_layer_id(), "Bits", patchy::LayerKind::Group);
    patchy::Layer child(document.allocate_layer_id(), "Dot", solid_rgba_square(2, 10, 250, 10, 255));
    child.set_bounds(patchy::Rect{1, 1, 2, 2});
    child.set_visible(false);
    group.add_child(std::move(child));
    document.add_layer(std::move(group));
  }

  const auto bytes = patchy::aseprite::DocumentIo::write(document);
  CHECK(patchy::aseprite::sniff(bytes));
  const auto read_back = patchy::aseprite::DocumentIo::read(bytes);
  CHECK(read_back.width() == 20);
  CHECK(read_back.height() == 20);
  CHECK(read_back.layers().size() == 3);
  CHECK(read_back.layers()[0].name() == "Backdrop");
  CHECK(read_back.layers()[1].name() == "Sprite");
  CHECK(read_back.layers()[1].blend_mode() == patchy::BlendMode::Multiply);
  CHECK(read_back.layers()[1].bounds().x == 7);
  CHECK(read_back.layers()[1].bounds().y == 3);
  CHECK(read_back.layers()[1].opacity() > 0.45F);
  CHECK(read_back.layers()[1].opacity() < 0.55F);
  CHECK(read_back.layers()[2].kind() == patchy::LayerKind::Group);
  CHECK(read_back.layers()[2].children().size() == 1);
  CHECK(!read_back.layers()[2].children()[0].visible());
  CHECK(read_back.layers()[1].pixels().pixel(2, 2)[0] == 220);

  // Palette-mode documents round trip as indexed with the document palette.
  patchy::Document indexed_doc(8, 4, patchy::PixelFormat::rgb8());
  const auto* preset = patchy::find_builtin_palette_preset("gameboy");
  CHECK(preset != nullptr);
  patchy::DocumentPaletteEditing editing;
  editing.palette.colors.assign(preset->colors.begin(), preset->colors.end());
  indexed_doc.palette_editing() = editing;
  patchy::PixelBuffer pixels(8, 4, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < 4; ++y) {
    for (std::int32_t x = 0; x < 8; ++x) {
      const auto& color = preset->colors[static_cast<std::size_t>(x % 4)];
      auto* px = pixels.pixel(x, y);
      px[0] = color.red;
      px[1] = color.green;
      px[2] = color.blue;
    }
  }
  indexed_doc.add_pixel_layer("Pixels", std::move(pixels));
  const auto indexed_bytes = patchy::aseprite::DocumentIo::write(indexed_doc);
  const auto indexed_back = patchy::aseprite::DocumentIo::read(indexed_bytes);
  CHECK(indexed_back.indexed_palette().has_value());
  for (std::int32_t x = 0; x < 8; ++x) {
    const auto& expected = preset->colors[static_cast<std::size_t>(x % 4)];
    const auto* px = indexed_back.layers().front().pixels().pixel(x, 1);
    CHECK(px[0] == expected.red);
    CHECK(px[1] == expected.green);
    CHECK(px[2] == expected.blue);
  }

  // Written to disk for the Aseprite CLI verification pass (Aseprite must open it).
  std::filesystem::create_directories("test-artifacts");
  patchy::aseprite::DocumentIo::write_file(document, "test-artifacts/aseprite_written.aseprite");
  patchy::aseprite::DocumentIo::write_file(indexed_doc, "test-artifacts/aseprite_written_indexed.aseprite");
}

void pcx_reads_8bit_indexed_and_24bit_rle() {
  const std::array<const char*, 3> names = {"pillow-rgb24.pcx", "pillow-indexed.pcx", "pillow-rgb24-odd.pcx"};
  for (const auto* name : names) {
    const auto path = patchy::test::committed_format_fixture_path("pcx", name);
    CHECK(std::filesystem::exists(path));
    const auto document = patchy::pcx::DocumentIo::read_file(path);
    CHECK(document.width() >= 47);
    CHECK(document.height() >= 31);
    const auto& pixels = document.layers().front().pixels();
    const auto* red = pixels.pixel(5, 5);
    CHECK(red[0] > 150);
    CHECK(red[1] < 100);
    const auto* background = pixels.pixel(40, 5);
    CHECK(background[2] > background[0]);
  }
  const auto indexed =
      patchy::pcx::DocumentIo::read_file(patchy::test::committed_format_fixture_path("pcx", "pillow-indexed.pcx"));
  CHECK(indexed.indexed_palette().has_value());
}

void pcx_write_read_round_trips() {
  // RGB path.
  patchy::Document document(21, 9, patchy::PixelFormat::rgb8());
  patchy::PixelBuffer pixels(21, 9, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < 9; ++y) {
    for (std::int32_t x = 0; x < 21; ++x) {
      auto* px = pixels.pixel(x, y);
      px[0] = static_cast<std::uint8_t>(x * 12);
      px[1] = static_cast<std::uint8_t>(y * 28);
      px[2] = static_cast<std::uint8_t>(200 - x * 3);
    }
  }
  document.add_pixel_layer("Art", pixels);
  const auto bytes = patchy::pcx::DocumentIo::write(document);
  CHECK(patchy::pcx::DocumentIo::can_read(bytes));
  const auto read_back = patchy::pcx::DocumentIo::read(bytes);
  CHECK(read_back.width() == 21);
  CHECK(read_back.height() == 9);
  for (std::int32_t y = 0; y < 9; ++y) {
    for (std::int32_t x = 0; x < 21; ++x) {
      const auto* expected = pixels.pixel(x, y);
      const auto* actual = read_back.layers().front().pixels().pixel(x, y);
      CHECK(actual[0] == expected[0]);
      CHECK(actual[1] == expected[1]);
      CHECK(actual[2] == expected[2]);
    }
  }

  // Palette-mode path: indexed PCX with the document palette at EOF.
  patchy::Document indexed_doc(8, 4, patchy::PixelFormat::rgb8());
  const auto* preset = patchy::find_builtin_palette_preset("gameboy");
  CHECK(preset != nullptr);
  patchy::DocumentPaletteEditing editing;
  editing.palette.colors.assign(preset->colors.begin(), preset->colors.end());
  indexed_doc.palette_editing() = editing;
  patchy::PixelBuffer indexed_pixels(8, 4, patchy::PixelFormat::rgb8());
  for (std::int32_t y = 0; y < 4; ++y) {
    for (std::int32_t x = 0; x < 8; ++x) {
      const auto& color = preset->colors[static_cast<std::size_t>(x % 4)];
      auto* px = indexed_pixels.pixel(x, y);
      px[0] = color.red;
      px[1] = color.green;
      px[2] = color.blue;
    }
  }
  indexed_doc.add_pixel_layer("Pixels", std::move(indexed_pixels));
  const auto indexed_bytes = patchy::pcx::DocumentIo::write(indexed_doc);
  const auto indexed_back = patchy::pcx::DocumentIo::read(indexed_bytes);
  CHECK(indexed_back.indexed_palette().has_value());
  for (std::int32_t x = 0; x < 8; ++x) {
    const auto& expected = preset->colors[static_cast<std::size_t>(x % 4)];
    const auto* px = indexed_back.layers().front().pixels().pixel(x, 2);
    CHECK(px[0] == expected.red);
    CHECK(px[1] == expected.green);
    CHECK(px[2] == expected.blue);
  }
  // Written to disk for the Pillow verification pass.
  std::filesystem::create_directories("test-artifacts");
  patchy::pcx::DocumentIo::write_file(document, "test-artifacts/pcx_written_rgb.pcx");
  patchy::pcx::DocumentIo::write_file(indexed_doc, "test-artifacts/pcx_written_indexed.pcx");
}

// Synthesizes a 4-plane ILBM byte-by-byte: 8x2, EHB off, ByteRun1 off (BODY raw),
// masking 2 (transparent color 3).
[[nodiscard]] std::vector<std::uint8_t> synthesize_ilbm_fixture() {
  patchy::psd::BigEndianWriter form;
  const auto put_id = [&form](const char* id) {
    for (int i = 0; i < 4; ++i) {
      form.write_u8(static_cast<std::uint8_t>(id[i]));
    }
  };
  put_id("FORM");
  form.write_u32(0);  // patched at the end
  put_id("ILBM");
  put_id("BMHD");
  form.write_u32(20);
  form.write_u16(8);
  form.write_u16(2);
  form.write_u16(0);
  form.write_u16(0);
  form.write_u8(4);   // planes
  form.write_u8(2);   // masking: transparent color
  form.write_u8(0);   // uncompressed
  form.write_u8(0);
  form.write_u16(3);  // transparent color
  form.write_u8(1);
  form.write_u8(1);
  form.write_u16(8);
  form.write_u16(2);
  put_id("CMAP");
  form.write_u32(16 * 3);
  for (int i = 0; i < 16; ++i) {
    form.write_u8(static_cast<std::uint8_t>(i * 16));
    form.write_u8(static_cast<std::uint8_t>(255 - i * 16));
    form.write_u8(static_cast<std::uint8_t>(i * 8));
  }
  put_id("BODY");
  // 2 rows x 4 planes x 2 bytes (8px word-aligned row). Row pixels: indexes 0..7 then 8..15.
  form.write_u32(2 * 4 * 2);
  const auto write_plane_rows = [&form](std::uint8_t base) {
    for (std::uint8_t plane = 0; plane < 4; ++plane) {
      std::uint8_t byte = 0;
      for (int x = 0; x < 8; ++x) {
        const auto index = static_cast<std::uint8_t>(base + x);
        byte = static_cast<std::uint8_t>(byte << 1U);
        byte |= (index >> plane) & 1U;
      }
      form.write_u8(byte);
      form.write_u8(0);  // word padding
    }
  };
  write_plane_rows(0);
  write_plane_rows(8);
  auto bytes = form.bytes();
  const auto form_size = static_cast<std::uint32_t>(bytes.size() - 8U);
  bytes[4] = static_cast<std::uint8_t>((form_size >> 24U) & 0xffU);
  bytes[5] = static_cast<std::uint8_t>((form_size >> 16U) & 0xffU);
  bytes[6] = static_cast<std::uint8_t>((form_size >> 8U) & 0xffU);
  bytes[7] = static_cast<std::uint8_t>(form_size & 0xffU);
  return bytes;
}

void ilbm_reads_planar_masked_body() {
  const auto bytes = synthesize_ilbm_fixture();
  CHECK(patchy::ilbm::DocumentIo::can_read(bytes));
  const auto document = patchy::ilbm::DocumentIo::read(bytes);
  CHECK(document.width() == 8);
  CHECK(document.height() == 2);
  CHECK(document.indexed_palette().has_value());
  CHECK(document.indexed_palette()->colors.size() == 16);
  const auto& pixels = document.layers().front().pixels();
  // Row 0 holds indexes 0..7: pixel x has color (16x, 255-16x, 8x); index 3 is transparent.
  CHECK(pixels.pixel(2, 0)[0] == 32);
  CHECK(pixels.pixel(2, 0)[1] == 255 - 32);
  CHECK(pixels.pixel(2, 0)[3] == 255);
  CHECK(pixels.pixel(3, 0)[3] == 0);  // transparent color
  CHECK(pixels.pixel(4, 1)[0] == 192);  // row 1 starts at index 8 -> x=4 is index 12
}

void ilbm_rejects_ham_with_message() {
  auto bytes = synthesize_ilbm_fixture();
  // Splice a CAMG chunk with the HAM bit right after the form type by rebuilding: simplest
  // is to flip masking? No — append CAMG before BODY is complex; instead patch a HAM CAMG
  // into a copy by replacing the CMAP id with CAMG (still parsed before BODY).
  // Cleaner: build a minimal HAM file.
  patchy::psd::BigEndianWriter form;
  const auto put_id = [&form](const char* id) {
    for (int i = 0; i < 4; ++i) {
      form.write_u8(static_cast<std::uint8_t>(id[i]));
    }
  };
  put_id("FORM");
  form.write_u32(0);
  put_id("ILBM");
  put_id("BMHD");
  form.write_u32(20);
  form.write_u16(4);
  form.write_u16(1);
  form.write_u16(0);
  form.write_u16(0);
  form.write_u8(6);
  form.write_u8(0);
  form.write_u8(0);
  form.write_u8(0);
  form.write_u16(0);
  form.write_u8(1);
  form.write_u8(1);
  form.write_u16(4);
  form.write_u16(1);
  put_id("CAMG");
  form.write_u32(4);
  form.write_u32(0x800);  // HAM
  put_id("CMAP");
  form.write_u32(3);
  form.write_u8(0);
  form.write_u8(0);
  form.write_u8(0);
  form.write_u8(0);  // pad
  put_id("BODY");
  form.write_u32(6 * 2);
  for (int i = 0; i < 12; ++i) {
    form.write_u8(0);
  }
  auto ham_bytes = form.bytes();
  const auto form_size = static_cast<std::uint32_t>(ham_bytes.size() - 8U);
  ham_bytes[7] = static_cast<std::uint8_t>(form_size & 0xffU);
  ham_bytes[6] = static_cast<std::uint8_t>((form_size >> 8U) & 0xffU);
  bool rejected = false;
  try {
    (void)patchy::ilbm::DocumentIo::read(ham_bytes);
  } catch (const std::exception& error) {
    rejected = std::string(error.what()).find("HAM") != std::string::npos;
  }
  CHECK(rejected);
}

void ilbm_write_read_round_trips_indexed() {
  patchy::Document document(19, 7, patchy::PixelFormat::rgba8());
  patchy::PixelBuffer pixels(19, 7, patchy::PixelFormat::rgba8());
  const std::array<patchy::RgbColor, 5> colors = {
      {{0, 0, 0}, {255, 255, 255}, {200, 30, 40}, {40, 60, 200}, {30, 180, 40}}};
  for (std::int32_t y = 0; y < 7; ++y) {
    for (std::int32_t x = 0; x < 19; ++x) {
      auto* px = pixels.pixel(x, y);
      if (x == 0 && y == 0) {
        px[3] = 0;  // one transparent pixel -> masking type 2
        continue;
      }
      const auto& color = colors[static_cast<std::size_t>((x + y) % colors.size())];
      px[0] = color.red;
      px[1] = color.green;
      px[2] = color.blue;
      px[3] = 255;
    }
  }
  document.add_pixel_layer("Art", pixels);
  const auto bytes = patchy::ilbm::DocumentIo::write(document);
  CHECK(patchy::ilbm::DocumentIo::can_read(bytes));
  const auto read_back = patchy::ilbm::DocumentIo::read(bytes);
  CHECK(read_back.width() == 19);
  CHECK(read_back.height() == 7);
  const auto& round = read_back.layers().front().pixels();
  CHECK(round.pixel(0, 0)[3] == 0);
  for (std::int32_t y = 0; y < 7; ++y) {
    for (std::int32_t x = 0; x < 19; ++x) {
      if (x == 0 && y == 0) {
        continue;
      }
      const auto& expected = colors[static_cast<std::size_t>((x + y) % colors.size())];
      const auto* actual = round.pixel(x, y);
      CHECK(actual[0] == expected.red);
      CHECK(actual[1] == expected.green);
      CHECK(actual[2] == expected.blue);
    }
  }
  std::filesystem::create_directories("test-artifacts");
  patchy::ilbm::DocumentIo::write_file(document, "test-artifacts/ilbm_written.lbm");
}

void format_registry_allows_read_only_handlers() {
  patchy::FormatRegistry registry;
  registry.register_handler({"patchy.test.readonly",
                             "Read Only",
                             {".ro"},
                             [](std::span<const std::uint8_t>) {
                               return patchy::FormatReadResult{
                                   patchy::Document(2, 2, patchy::PixelFormat::rgba8()), {"notice"}};
                             },
                             nullptr,
                             nullptr});
  const auto* handler = registry.find_by_extension(".ro");
  CHECK(handler != nullptr);
  CHECK(!handler->can_write());
  const auto result = handler->read({});
  CHECK(result.notices.size() == 1);

  bool rejected_readless = false;
  try {
    registry.register_handler({"patchy.test.noread", "No Read", {".nr"}, nullptr, nullptr, nullptr});
  } catch (const std::invalid_argument&) {
    rejected_readless = true;
  }
  CHECK(rejected_readless);

  CHECK(patchy::builtin_format_registry().find_by_extension(".bmp") != nullptr);
  CHECK(patchy::builtin_format_registry().find_by_extension(".bmp")->can_write());
}

// ---- Camera raw (vendored LibRaw behind formats/raw_document_io) ----
//
// The synthetic fixture is a minimal uncompressed 16-bit Bayer DNG built byte-by-byte
// (tests/synthetic_dng.hpp; the house adversarial-file pattern), so the raw pipeline is
// exercised on every platform with no committed camera files. Assertions are statistical
// (dimensions, channel means, monotonic responses) — LibRaw's float pipeline is NOT
// byte-stable across toolchains, so exact-hash pinning is deliberately avoided (AGENTS.md
// determinism rules).

using patchy::test::synthetic_bayer_dng;
using patchy::test::SyntheticDngOptions;

struct RawChannelMeans {
  double red{0.0};
  double green{0.0};
  double blue{0.0};
};

RawChannelMeans raw_channel_means(const patchy::Document& document) {
  const auto& pixels = document.layers().front().pixels();
  RawChannelMeans means;
  const auto pixel_count =
      static_cast<double>(pixels.width()) * static_cast<double>(pixels.height());
  for (std::int32_t y = 0; y < pixels.height(); ++y) {
    for (std::int32_t x = 0; x < pixels.width(); ++x) {
      const auto* px = pixels.pixel(x, y);
      means.red += px[0];
      means.green += px[1];
      means.blue += px[2];
    }
  }
  means.red /= pixel_count;
  means.green /= pixel_count;
  means.blue /= pixel_count;
  return means;
}

void raw_white_balance_round_trips_temperature_and_tint() {
  // The inverse (multipliers -> kelvin/tint) must recover what the forward direction
  // produced; run a spread of plausible photographic values through the sRGB fallback
  // matrix and a Canon-ish matrix.
  const patchy::raw::CameraMatrix canonish = {{
      {{0.6844, -0.0996, -0.0856}},
      {{-0.3876, 1.1761, 0.2396}},
      {{-0.0593, 0.1772, 0.6198}},
      {{0.0, 0.0, 0.0}},
  }};
  const std::array<patchy::raw::CameraMatrix, 2> matrices = {patchy::raw::CameraMatrix{}, canonish};
  const std::array<patchy::raw::WhiteBalance, 5> cases = {{
      {2850.0, 0.0},
      {3800.0, 21.0},
      {5500.0, 10.0},
      {6500.0, -20.0},
      {12000.0, 0.0},
  }};
  for (const auto& matrix : matrices) {
    for (const auto& expected : cases) {
      const auto multipliers = patchy::raw::multipliers_for_white_balance(expected, matrix);
      CHECK(multipliers[0] > 0.0);
      CHECK(multipliers[1] == 1.0);
      CHECK(multipliers[2] > 0.0);
      const auto recovered = patchy::raw::white_balance_for_multipliers(multipliers, matrix);
      CHECK(recovered.has_value());
      CHECK(std::abs(recovered->temperature_k - expected.temperature_k) <
            expected.temperature_k * 0.02);
      CHECK(std::abs(recovered->tint - expected.tint) < 3.0);
    }
  }
}

void raw_develop_reads_synthetic_dng() {
  // Camera-raw defaults are deliberately neutral: no auto histogram stretch.
  CHECK(!patchy::raw::DevelopParams{}.auto_brighten);

  const auto dng = synthetic_bayer_dng(128, 96);
  patchy::raw::DevelopParams params;
  params.auto_brighten = false;  // a uniform field would auto-stretch to white
  auto result = patchy::raw::read_camera_raw(dng, params);
  CHECK(result.document.width() == 128);
  CHECK(result.document.height() == 96);
  CHECK(result.document.layers().size() == 1);
  CHECK(result.document.layers().front().name() == "Background");
  CHECK(result.document.format().bit_depth == patchy::BitDepth::UInt8);
  // A gray card under the as-shot illuminant develops to a near-neutral mid tone
  // (borders excluded by averaging the whole frame; demosaic edges are a tiny fraction).
  const auto means = raw_channel_means(result.document);
  CHECK(means.green > 40.0);
  CHECK(means.green < 220.0);
  CHECK(std::abs(means.red - means.green) < 14.0);
  CHECK(std::abs(means.blue - means.green) < 14.0);

  // Registry dispatch: .dng routes to the read-only camera raw handler.
  const auto* handler = patchy::builtin_format_registry().find_by_extension(".dng");
  CHECK(handler != nullptr);
  CHECK(!handler->can_write());
  CHECK(patchy::raw::is_camera_raw_extension("cr3"));
  CHECK(!patchy::raw::is_camera_raw_extension("raw"));
  const auto via_registry = handler->read(dng);
  CHECK(via_registry.document.width() == 128);
  CHECK(via_registry.document.height() == 96);
}

void raw_develop_exposure_and_white_balance_shift_output() {
  const auto dng = synthetic_bayer_dng(128, 96);
  patchy::raw::DevelopParams params;
  params.auto_brighten = false;
  const auto base = raw_channel_means(patchy::raw::read_camera_raw(dng, params).document);

  auto brighter_params = params;
  brighter_params.exposure_ev = 1.5;
  const auto brighter = raw_channel_means(patchy::raw::read_camera_raw(dng, brighter_params).document);
  CHECK(brighter.green > base.green + 8.0);

  auto darker_params = params;
  darker_params.exposure_ev = -1.5;
  const auto darker = raw_channel_means(patchy::raw::read_camera_raw(dng, darker_params).document);
  CHECK(darker.green + 8.0 < base.green);

  // Raising the temperature renders warmer (more red, less blue) than lowering it.
  auto warm_params = params;
  warm_params.white_balance = patchy::raw::WhiteBalanceMode::Custom;
  warm_params.custom_white_balance = {8000.0, 0.0};
  auto cool_params = warm_params;
  cool_params.custom_white_balance = {3000.0, 0.0};
  const auto warm = raw_channel_means(patchy::raw::read_camera_raw(dng, warm_params).document);
  const auto cool = raw_channel_means(patchy::raw::read_camera_raw(dng, cool_params).document);
  CHECK(warm.red - warm.blue > cool.red - cool.blue + 10.0);
}

void raw_tone_lut_and_color_math() {
  // Neutral parameters must be an exact identity table.
  const auto identity = patchy::raw::build_tone_lut({});
  for (const int index : {0, 1, 255, 12345, 32768, 54321, 65534, 65535}) {
    CHECK(identity[static_cast<std::size_t>(index)] == index);
  }

  // Contrast: S-curve around the midpoint, endpoints pinned.
  patchy::raw::ToneParams contrast;
  contrast.contrast = 100.0;
  const auto contrasty = patchy::raw::build_tone_lut(contrast);
  CHECK(contrasty[16384] < 16384);
  CHECK(contrasty[49151] > 49151);
  CHECK(contrasty[0] == 0);
  CHECK(contrasty[65535] == 65535);
  contrast.contrast = -100.0;
  const auto flat = patchy::raw::build_tone_lut(contrast);
  CHECK(flat[16384] > 16384);
  CHECK(flat[49151] < 49151);

  // Shadows: lifts the dark band, pins pure black, leaves highlights alone.
  patchy::raw::ToneParams shadows;
  shadows.shadows = 100.0;
  const auto lifted = patchy::raw::build_tone_lut(shadows);
  CHECK(lifted[0] == 0);
  CHECK(lifted[9830] > 9830 + 3000);   // 0.15: band center clearly lifted
  CHECK(lifted[58982] == 58982);       // 0.9: untouched

  // Highlights: negative values dim the bright end (including full white) and leave
  // shadows alone.
  patchy::raw::ToneParams highlights;
  highlights.highlights = -100.0;
  const auto recovered = patchy::raw::build_tone_lut(highlights);
  CHECK(recovered[65535] < 65535 - 10000);
  CHECK(recovered[6553] == 6553);  // 0.1: untouched

  // Saturation converges channels to luma at -100 and widens the spread at +100;
  // vibrance moves an already-saturated pixel LESS than plain saturation does.
  const std::array<std::uint16_t, 3> source = {40000, 20000, 10000};
  auto desaturated = source;
  patchy::raw::apply_color(std::span<std::uint16_t>(desaturated), -100.0, 0.0);
  CHECK(std::abs(int(desaturated[0]) - int(desaturated[1])) <= 1);
  CHECK(std::abs(int(desaturated[2]) - int(desaturated[1])) <= 1);
  auto saturated = source;
  patchy::raw::apply_color(std::span<std::uint16_t>(saturated), 80.0, 0.0);
  auto vibrant = source;
  patchy::raw::apply_color(std::span<std::uint16_t>(vibrant), 0.0, 80.0);
  const auto source_spread = int(source[0]) - int(source[2]);
  const auto saturated_spread = int(saturated[0]) - int(saturated[2]);
  const auto vibrant_spread = int(vibrant[0]) - int(vibrant[2]);
  CHECK(saturated_spread > source_spread);
  CHECK(vibrant_spread > source_spread);
  CHECK(vibrant_spread < saturated_spread);
}

void raw_develop_tone_and_color_controls_shift_output() {
  // Bright ramp (0 -> 90% full scale): distinct shadow and highlight regions.
  SyntheticDngOptions ramp;
  ramp.red_value = 58982;
  ramp.green_value = 58982;
  ramp.blue_value = 58982;
  ramp.horizontal_ramp = true;
  const auto ramp_dng = synthetic_bayer_dng(128, 96, ramp);

  const auto quarter_green_mean = [](const patchy::Document& document, bool right_quarter) {
    const auto& pixels = document.layers().front().pixels();
    const auto begin_x = right_quarter ? pixels.width() * 3 / 4 : 0;
    const auto end_x = right_quarter ? pixels.width() : pixels.width() / 4;
    double total = 0.0;
    for (std::int32_t y = 0; y < pixels.height(); ++y) {
      for (std::int32_t x = begin_x; x < end_x; ++x) {
        total += pixels.pixel(x, y)[1];
      }
    }
    return total / (static_cast<double>(end_x - begin_x) * pixels.height());
  };

  patchy::raw::DevelopParams neutral;
  const auto base = patchy::raw::read_camera_raw(ramp_dng, neutral).document;
  const auto base_dark = quarter_green_mean(base, false);
  const auto base_bright = quarter_green_mean(base, true);
  CHECK(base_dark > 5.0);
  CHECK(base_bright > base_dark + 60.0);

  auto contrast_params = neutral;
  contrast_params.contrast = 80.0;
  const auto contrasty = patchy::raw::read_camera_raw(ramp_dng, contrast_params).document;
  CHECK(quarter_green_mean(contrasty, false) < base_dark - 4.0);
  CHECK(quarter_green_mean(contrasty, true) > base_bright + 1.0);

  auto shadow_params = neutral;
  shadow_params.shadows = 80.0;
  const auto shadow_lifted = patchy::raw::read_camera_raw(ramp_dng, shadow_params).document;
  const auto lifted_dark_delta = quarter_green_mean(shadow_lifted, false) - base_dark;
  const auto lifted_bright_delta = std::abs(quarter_green_mean(shadow_lifted, true) - base_bright);
  CHECK(lifted_dark_delta > 8.0);
  CHECK(lifted_bright_delta < 2.0);

  auto highlight_params = neutral;
  highlight_params.highlights = -80.0;
  const auto highlight_recovered = patchy::raw::read_camera_raw(ramp_dng, highlight_params).document;
  const auto recovered_bright_delta = base_bright - quarter_green_mean(highlight_recovered, true);
  const auto recovered_dark_delta = std::abs(base_dark - quarter_green_mean(highlight_recovered, false));
  CHECK(recovered_bright_delta > 20.0);
  CHECK(recovered_dark_delta * 4.0 < recovered_bright_delta);

  // Colored scene (red-heavy) for the color controls.
  SyntheticDngOptions colored;
  colored.red_value = 23592;
  colored.green_value = 11796;
  colored.blue_value = 5898;
  const auto colored_dng = synthetic_bayer_dng(128, 96, colored);
  const auto colored_base = raw_channel_means(patchy::raw::read_camera_raw(colored_dng, neutral).document);
  const auto base_spread = colored_base.red - colored_base.blue;
  CHECK(base_spread > 20.0);

  auto desaturate_params = neutral;
  desaturate_params.saturation = -100.0;
  const auto gray = raw_channel_means(patchy::raw::read_camera_raw(colored_dng, desaturate_params).document);
  CHECK(std::abs(gray.red - gray.green) < 3.0);
  CHECK(std::abs(gray.blue - gray.green) < 3.0);

  auto saturate_params = neutral;
  saturate_params.saturation = 80.0;
  const auto vivid = raw_channel_means(patchy::raw::read_camera_raw(colored_dng, saturate_params).document);
  auto vibrance_params = neutral;
  vibrance_params.vibrance = 80.0;
  const auto vibrant = raw_channel_means(patchy::raw::read_camera_raw(colored_dng, vibrance_params).document);
  const auto vivid_spread = vivid.red - vivid.blue;
  const auto vibrant_spread = vibrant.red - vibrant.blue;
  CHECK(vivid_spread > base_spread + 8.0);
  CHECK(vibrant_spread > base_spread + 2.0);
  // Vibrance holds back on an already-saturated subject.
  CHECK(vibrant_spread < vivid_spread);
}

void raw_develop_half_size_and_denoise_run() {
  const auto dng = synthetic_bayer_dng(128, 96);
  patchy::raw::DevelopParams params;
  params.auto_brighten = false;
  params.half_size = true;
  const auto half = patchy::raw::read_camera_raw(dng, params).document;
  CHECK(half.width() == 64);
  CHECK(half.height() == 48);

  // The remaining pipeline stages must at least run cleanly end to end.
  patchy::raw::DevelopParams heavy;
  heavy.auto_brighten = true;
  heavy.exposure_ev = 0.5;
  heavy.highlight_recovery = patchy::raw::HighlightMode::Rebuild;
  heavy.demosaic = patchy::raw::DemosaicAlgorithm::Dht;
  heavy.wavelet_denoise_threshold = 300;
  heavy.fbdd = patchy::raw::FbddNoiseReduction::Full;
  const auto processed = patchy::raw::read_camera_raw(dng, heavy).document;
  CHECK(processed.width() == 128);
  CHECK(processed.height() == 96);
}

void raw_develop_session_reports_info_and_orientation() {
  SyntheticDngOptions options;
  options.orientation = 6;  // rotate 90 CW: output swaps to portrait
  const auto dng = synthetic_bayer_dng(128, 96, options);
  patchy::raw::DevelopSession session(std::vector<std::uint8_t>(dng.begin(), dng.end()));
  const auto& info = session.info();
  CHECK(info.camera_model.find("Synthetic") != std::string::npos);
  CHECK(info.output_width == 96);
  CHECK(info.output_height == 128);
  CHECK(info.orientation_flip == 6);
  CHECK(!info.is_xtrans);
  // AsShotNeutral encodes D65 through the sRGB matrix; the derived display value must
  // land near daylight with a small tint.
  CHECK(info.as_shot_white_balance.has_value());
  CHECK(info.as_shot_white_balance->temperature_k > 5000.0);
  CHECK(info.as_shot_white_balance->temperature_k < 8000.0);
  CHECK(std::abs(info.as_shot_white_balance->tint) < 15.0);

  patchy::raw::DevelopParams params;
  params.auto_brighten = false;
  const auto developed = session.develop(params);
  CHECK(developed.width == 96);
  CHECK(developed.height == 128);
  // Re-develop with new parameters on the same session (the preview loop's contract).
  auto brighter = params;
  brighter.exposure_ev = 1.0;
  const auto second = session.develop(brighter);
  CHECK(second.width == 96);
  CHECK(second.height == 128);
}

void raw_develop_rejects_non_raw_bytes() {
  bool rejected = false;
  try {
    const std::vector<std::uint8_t> garbage(4096, 0x5A);
    (void)patchy::raw::read_camera_raw(garbage, {});
  } catch (const std::exception& error) {
    rejected = true;
    CHECK(std::string(error.what()).find("not a supported camera raw file") != std::string::npos);
  }
  CHECK(rejected);

  // A structurally valid DNG whose pixel strip is cut short must error, not crash.
  auto truncated = synthetic_bayer_dng(128, 96);
  truncated.resize(truncated.size() - 128 * 96);  // drop half the samples
  bool truncated_rejected = false;
  try {
    (void)patchy::raw::read_camera_raw(truncated, {});
  } catch (const std::exception&) {
    truncated_rejected = true;
  }
  CHECK(truncated_rejected);
}

void raw_decodes_real_camera_samples_if_available() {
  const auto directory = patchy::test::source_root_path() / "local-test-fixtures" / "raw";
  if (!std::filesystem::exists(directory)) {
    std::cout << "[SKIP] local raw fixtures missing: " << directory.string() << '\n';
    return;
  }
  std::size_t decoded = 0;
  for (const auto& entry : std::filesystem::directory_iterator(directory)) {
    if (!entry.is_regular_file()) {
      continue;
    }
    auto extension = entry.path().extension().string();
    if (!extension.empty() && extension.front() == '.') {
      extension.erase(extension.begin());
    }
    std::transform(extension.begin(), extension.end(), extension.begin(),
                   [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
    if (!patchy::raw::is_camera_raw_extension(extension)) {
      continue;
    }
    std::ifstream stream(entry.path(), std::ios::binary);
    std::vector<std::uint8_t> bytes((std::istreambuf_iterator<char>(stream)),
                                    std::istreambuf_iterator<char>());
    patchy::raw::DevelopSession session(std::move(bytes));
    CHECK(session.info().output_width > 0);
    CHECK(session.info().output_height > 0);
    patchy::raw::DevelopParams params;
    params.half_size = true;  // keep the suite fast on 40+ MP samples
    const auto developed = session.develop(params);
    CHECK(developed.width > 0);
    CHECK(developed.height > 0);
    ++decoded;
    std::cout << "[INFO] developed " << entry.path().filename().string() << " ("
              << session.info().camera_make << ' ' << session.info().camera_model << ", "
              << developed.width << 'x' << developed.height << " half size)\n";
  }
  CHECK(decoded > 0);
}

void heif_extensions_sniff_and_registry_routing() {
  CHECK(patchy::heif::is_heif_extension("heic"));
  CHECK(patchy::heif::is_heif_extension(".HEIF"));
  CHECK(patchy::heif::is_heif_extension("hif"));
  CHECK(!patchy::heif::is_heif_extension("jpg"));

  // Registry dispatch is read-only (no writer), which is what routes Save to Save As.
  const auto* handler = patchy::builtin_format_registry().find_by_extension(".heic");
  CHECK(handler != nullptr);
  CHECK(!handler->can_write());
  CHECK(patchy::builtin_format_registry().find_by_extension(".hif") == handler);

  // The committed fixture (authored from a Patchy PNG via macOS sips) is brand "heic".
  const auto fixture =
      read_binary_file(patchy::test::committed_format_fixture_path("heif", "quadrants.heic"));
  CHECK(fixture.size() > 16);
  CHECK(patchy::heif::sniff(fixture));

  const auto synthetic_ftyp = [](std::string_view brand) {
    std::vector<std::uint8_t> bytes = {0, 0, 0, 16, 'f', 't', 'y', 'p'};
    bytes.insert(bytes.end(), brand.begin(), brand.end());
    bytes.insert(bytes.end(), {0, 0, 0, 0});
    return bytes;
  };
  CHECK(patchy::heif::sniff(synthetic_ftyp("heix")));  // Sony/Fuji .hif
  CHECK(patchy::heif::sniff(synthetic_ftyp("msf1")));
  // AVIF shares the container but is deliberately not routed to the HEIF reader.
  CHECK(!patchy::heif::sniff(synthetic_ftyp("avif")));
  const std::vector<std::uint8_t> png_magic = {0x89, 'P', 'N', 'G', '\r', '\n', 0x1a, '\n',
                                               0,    0,   0,   13,  'I',  'H',  'D',  'R'};
  CHECK(!patchy::heif::sniff(png_magic));
}

void heif_orientation_mapping_matches_exif_semantics() {
  // 2x2 source (red channel carries the pixel id):  1 2 / 3 4.
  std::vector<std::uint8_t> source;
  for (std::uint8_t id = 1; id <= 4; ++id) {
    source.insert(source.end(), {id, 0, 0, 255});
  }
  const auto red_at = [](const patchy::heif::OrientedImage& image, std::int32_t x, std::int32_t y) {
    return image.rgba[(static_cast<std::size_t>(y) * static_cast<std::size_t>(image.width) +
                       static_cast<std::size_t>(x)) *
                      4U];
  };
  // Expected row-major ids per EXIF orientation, derived from "value describes where the
  // stored 0th row/column appear visually".
  const std::array<std::array<std::uint8_t, 4>, 9> expected = {{
      {1, 2, 3, 4},  // [0] unused
      {1, 2, 3, 4},  // 1 identity
      {2, 1, 4, 3},  // 2 mirrored horizontally
      {4, 3, 2, 1},  // 3 rotated 180
      {3, 4, 1, 2},  // 4 mirrored vertically
      {1, 3, 2, 4},  // 5 transposed
      {3, 1, 4, 2},  // 6 rotate 90 CW to display
      {4, 2, 3, 1},  // 7 transverse
      {2, 4, 1, 3},  // 8 rotate 90 CCW to display
  }};
  for (int orientation = 1; orientation <= 8; ++orientation) {
    const auto oriented = patchy::heif::apply_exif_orientation(source, 2, 2, orientation);
    CHECK(oriented.width == 2);
    CHECK(oriented.height == 2);
    for (std::int32_t index = 0; index < 4; ++index) {
      CHECK(red_at(oriented, index % 2, index / 2) ==
            expected[static_cast<std::size_t>(orientation)][static_cast<std::size_t>(index)]);
    }
  }

  // Orientations 5-8 swap the dimensions: a 2x3 source rotated 90 CW displays as 3x2.
  std::vector<std::uint8_t> tall;
  for (std::uint8_t id = 1; id <= 6; ++id) {
    tall.insert(tall.end(), {id, 0, 0, 255});
  }
  const auto rotated = patchy::heif::apply_exif_orientation(tall, 2, 3, 6);
  CHECK(rotated.width == 3);
  CHECK(rotated.height == 2);
  const std::array<std::uint8_t, 6> rotated_expected = {5, 3, 1, 6, 4, 2};
  for (std::int32_t index = 0; index < 6; ++index) {
    CHECK(red_at(rotated, index % 3, index / 3) == rotated_expected[static_cast<std::size_t>(index)]);
  }

  // Out-of-range values are treated as "no orientation", matching the reader's fallback.
  const auto passthrough = patchy::heif::apply_exif_orientation(source, 2, 2, 0);
  CHECK(passthrough.rgba == std::vector<std::uint8_t>(source.begin(), source.end()));
}

void heif_reads_quadrant_fixture_if_available() {
  const auto bytes =
      read_binary_file(patchy::test::committed_format_fixture_path("heif", "quadrants.heic"));
  CHECK(!bytes.empty());
  patchy::FormatReadResult result;
  try {
    result = patchy::heif::read_heif(bytes);
  } catch (const std::exception& error) {
    // Expected wherever no platform decoder exists: the non-Windows read always throws
    // (macOS/Linux decode through Qt plugins the core suite does not link), and Windows
    // throws marker-prefixed errors when the Store codec packages are absent. Anything
    // else is a real failure.
    const std::string message = error.what();
    const auto starts_with = [&message](std::string_view prefix) {
      return message.rfind(std::string(prefix), 0) == 0;
    };
    if (starts_with(patchy::heif::kHeifPackageMissingMarker) ||
        starts_with(patchy::heif::kHevcPackageMissingMarker) ||
        message.find("system codec") != std::string::npos ||
        message.find("Flatpak codec extension") != std::string::npos) {
      std::cout << "[SKIP] HEIC platform decoder unavailable: " << message << '\n';
      return;
    }
    throw;
  }

  CHECK(result.document.width() == 64);
  CHECK(result.document.height() == 48);
  CHECK(result.document.layers().size() == 1);
  CHECK(result.document.layers().front().name() == "Background");

  // Statistics only, never byte pins: HEVC decode is lossy-coded (4:2:0) and the color
  // conversion runs through the platform CMS. Sample quadrant interiors (6 px inset keeps
  // chroma-subsampling edge bleed out of the means).
  const auto& pixels = std::as_const(result.document.layers().front()).pixels();
  const auto channels = pixels.format().channels;
  CHECK(channels >= 3);
  const auto quadrant_mean = [&](std::int32_t x0, std::int32_t y0) {
    double sums[3] = {0.0, 0.0, 0.0};
    int count = 0;
    for (std::int32_t y = y0 + 6; y < y0 + 24 - 6; ++y) {
      for (std::int32_t x = x0 + 6; x < x0 + 32 - 6; ++x) {
        const auto* px = pixels.pixel(x, y);
        for (int channel = 0; channel < 3; ++channel) {
          sums[channel] += px[channel];
        }
        ++count;
      }
    }
    return std::array<double, 3>{sums[0] / count, sums[1] / count, sums[2] / count};
  };
  const auto top_left = quadrant_mean(0, 0);       // red
  const auto top_right = quadrant_mean(32, 0);     // green
  const auto bottom_left = quadrant_mean(0, 24);   // blue
  const auto bottom_right = quadrant_mean(32, 24); // white
  CHECK(top_left[0] > 200.0);
  CHECK(top_left[1] < 80.0);
  CHECK(top_left[2] < 80.0);
  CHECK(top_right[1] > 200.0);
  CHECK(top_right[0] < 100.0);
  CHECK(top_right[2] < 100.0);
  CHECK(bottom_left[2] > 200.0);
  CHECK(bottom_left[0] < 80.0);
  CHECK(bottom_left[1] < 80.0);
  CHECK(bottom_right[0] > 200.0);
  CHECK(bottom_right[1] > 200.0);
  CHECK(bottom_right[2] > 200.0);
}

void heif_decodes_real_photos_if_available() {
  // Real HEICs (e.g. iPhone captures: Display P3, camera orientation) live in the
  // untracked local fixtures; remotes and codec-less machines [SKIP].
  const auto directory = patchy::test::source_root_path() / "local-test-fixtures" / "heif";
  if (!std::filesystem::exists(directory)) {
    std::cout << "[SKIP] local heif fixtures missing: " << directory.string() << '\n';
    return;
  }
  std::size_t decoded = 0;
  for (const auto& entry : std::filesystem::directory_iterator(directory)) {
    if (!entry.is_regular_file()) {
      continue;
    }
    auto extension = entry.path().extension().string();
    if (!extension.empty() && extension.front() == '.') {
      extension.erase(extension.begin());
    }
    std::transform(extension.begin(), extension.end(), extension.begin(),
                   [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
    if (!patchy::heif::is_heif_extension(extension)) {
      continue;
    }
    const auto bytes = read_binary_file(entry.path());
    CHECK(patchy::heif::sniff(bytes));
    try {
      const auto result = patchy::heif::read_heif(bytes);
      CHECK(result.document.width() > 0);
      CHECK(result.document.height() > 0);
      // quadrants-p3.heic is the committed quadrant art re-encoded through the Display P3
      // profile (macOS sips --matchTo). Its top-left quadrant stores sRGB-pure red as P3
      // coordinates (~234, 51, 35); only a decoder that APPLIES the embedded profile
      // returns ~ (255, 0, 0), so these thresholds pin the ICC -> sRGB conversion (an
      // unmanaged decode reads green ~51 and fails).
      if (entry.path().filename().string().rfind("quadrants-p3", 0) == 0) {
        const auto& pixels = std::as_const(result.document.layers().front()).pixels();
        double red_sum = 0.0;
        double green_sum = 0.0;
        int count = 0;
        for (std::int32_t y = 6; y < 18; ++y) {
          for (std::int32_t x = 6; x < 26; ++x) {
            const auto* px = pixels.pixel(x, y);
            red_sum += px[0];
            green_sum += px[1];
            ++count;
          }
        }
        CHECK(red_sum / count > 245.0);
        CHECK(green_sum / count < 30.0);
      }
      ++decoded;
      std::cout << "[INFO] decoded " << entry.path().filename().string() << " ("
                << result.document.width() << 'x' << result.document.height() << ")\n";
    } catch (const std::exception& error) {
      std::cout << "[SKIP] HEIC platform decoder unavailable: " << error.what() << '\n';
      return;
    }
  }
  CHECK(decoded > 0);
}

