  CHECK(patchy::ascii_lower_copy("BackGround") == "background");
  CHECK(patchy::normalized_extension("PSD") == ".psd");
  CHECK(patchy::normalized_extension(".8BF") == ".8bf");
  CHECK(patchy::normalized_extension(".PNG", false) == "png");
